def _esc(s):
    """XSS 방지 — 사용자/외부 입력(이름·영상제목·공지 등)을 raw HTML에 넣기 전 이스케이프.
    줄바꿈은 <br>로 보존."""
    return _html.escape(str(s if s is not None else "")).replace("\n", "<br>")
