# ════════ 🔐 불투명 세션ID — URL에 실제 refresh_token 대신 폐기·만료 가능한 랜덤ID ════════
#  방어적 설계: app_sessions 테이블이 없거나 실패하면 기존(raw 토큰) 동작으로 자동 폴백.
_APP_SESSION_TTL_DAYS = 7
def _create_app_session(refresh_token, email):
    """불투명 세션ID 생성 → app_sessions 저장, ID 반환. 실패 시 None(폴백 유도)."""
    try:
        _sid = _secrets.token_urlsafe(32)
        _exp = (datetime.now() + timedelta(days=_APP_SESSION_TTL_DAYS)).isoformat()
        supabase.table("app_sessions").insert({
            "id": _sid, "refresh_token": refresh_token,
            "user_email": email or "", "expires_at": _exp,
        }).execute()
        return _sid
    except Exception:
        return None

def _lookup_app_session(sid):
    """불투명ID → refresh_token 조회(만료 확인). 없으면 None(raw 폴백 유도)."""
    if not sid:
        return None
    try:
        r = supabase.table("app_sessions").select("refresh_token,expires_at").eq("id", sid).limit(1).execute()
        if r.data:
            _row = r.data[0]
            _exp = _row.get("expires_at")
            if _exp and str(_exp) < datetime.now().isoformat():
                _delete_app_session(sid)
                return None
            return _row.get("refresh_token")
    except Exception:
        pass
    return None

def _delete_app_session(sid):
    if not sid:
        return
    try:
        supabase.table("app_sessions").delete().eq("id", sid).execute()
    except Exception:
        pass

def _set_session_param(refresh_token, email, old_sid=None):
    """세션 URL 파라미터 설정 — 불투명ID 우선, 실패 시 raw 토큰 폴백. old_sid는 회전(폐기)."""
    _opaque = _create_app_session(refresh_token, email)
    if _opaque:
        st.query_params["sid"] = _opaque
        if old_sid and old_sid != _opaque:
            _delete_app_session(old_sid)
    else:
        st.query_params["sid"] = refresh_token  # 폴백: app_sessions 미생성 시 기존 동작 유지

# ─── 관리자 전용(service_role) 클라이언트 ─────────────────────────
#  SUPABASE_KEY는 일반적으로 anon 키 — auth.admin.* 등 일부 엔드포인트는
#  service_role 키가 필요하다. SUPABASE_SERVICE_ROLE_KEY가 .env에 있으면
#  별도 클라이언트로 캐싱하고, 없으면 일반 supabase 폴백(실패 가능).
_sb_admin_cached = None
def _service_role_key():
    """service_role 키 읽기 — 새 이름 DRAGON_SR_KEY 우선, 구 SUPABASE_SERVICE_ROLE_KEY 폴백.
    ※ Railway의 Supabase 연동이 SUPABASE_* 네임스페이스를 관리/덮어쓸 수 있어 접두사 없는 새 이름 사용."""
    return (os.getenv("DRAGON_SR_KEY") or os.getenv("SUPABASE_SERVICE_ROLE_KEY") or "").strip()
def sb_admin():
    """관리자 작업 전용 Supabase 클라이언트 (auth.admin.create_user 등).

    .env에 SUPABASE_SERVICE_ROLE_KEY가 설정돼 있으면 service_role 키로 만든
    별도 클라이언트를 캐싱·반환. 없으면 anon 클라이언트 폴백 (admin 엔드포인트
    호출 시 'requires a valid Bearer token' 에러 발생할 수 있음).
    """
    global _sb_admin_cached
    if _sb_admin_cached is not None:
        return _sb_admin_cached
    _srk = _service_role_key()
    if _srk:
        try:
            _sb_admin_cached = create_client((os.getenv("SUPABASE_URL") or "").strip(), _srk)
        except Exception:
            _sb_admin_cached = supabase
    else:
        _sb_admin_cached = supabase
    return _sb_admin_cached
# ════════════════════════════════════════════════════════════════════
# Phase 3 마이그레이션 헬퍼 (5/10 추가)
# 듀얼 리드: partner_id 우선, agency_id 폴백
# Phase 4에서 agency_id 폴백 제거 예정
# ════════════════════════════════════════════════════════════════════
def get_partner_id_for_user(user):
    """Phase 3 듀얼 리드 헬퍼. partner_id 우선, agency_id 폴백."""
    if not user:
        return None
    partner_id = user.get("partner_id")
    if partner_id:
        return partner_id
    return user.get("agency_id")


def get_user_partner_id_from_db(user_email):
    """DB에서 직접 조회 (캐시 없을 때)."""
    if not user_email:
        return None
    try:
        result = supabase.table("users").select(
            "partner_id, agency_id"
        ).eq("email", user_email).is_("deleted_at", "null").execute()
        if not result.data:
            return None
        row = result.data[0]
        return row.get("partner_id") or row.get("agency_id")
    except Exception as e:
        print(f"[get_user_partner_id_from_db] Error: {e}")
        return None



