def t(key, *args):
    lang = st.session_state.get("lang", "ko")
    text = LANG.get(lang, LANG["ko"]).get(key, LANG["ko"].get(key, key))
    if args:
        try: return text.format(*args)
        except: return text
    return text

defaults = {
    "user": None,
    "access_token": None,
    "refresh_token": None,
    "report_count": 0,
    "lang": "ko",
    "current_page": "home_landing",
    "prev_page": "home_landing",
    "active_tab": 0,
    "prefill_content": "",
    "prefill_result": "",
    "prefill_severity": 1,
    "prefill_category": "안전",
    "prefill_platform": "YouTube",
    "selected_report": None,
    "search_results": [],
    "recommend_results": [],
    "chat_history": [],
    "dragon_fullscreen": False,
    "contact_hq_recipient": "kingcas7@gmail.com",
}
for k, v in defaults.items():
    if k not in st.session_state:
        st.session_state[k] = v

# ── 새로고침 세션 복원 ──
params = st.query_params

# 동의 페이지 직접 접근 처리 (로그인 없이 접근 가능)
if "req_id" in params and st.session_state.get("current_page") != "consent_page":
    st.session_state.current_page = "consent_page"

# ⭐ Phase 7+8: 설문 토큰으로 직접 접근 (비로그인 가능)
if "survey_token" in params:
    _stoken = params.get("survey_token")
    if _stoken:
        st.session_state["_survey_token"] = _stoken
        st.session_state["current_page"] = "survey_respond"

# 🔑 커스텀 비밀번호 재설정 토큰 링크 (Resend로 보낸 자체 링크 — Supabase 설정 무관)
if "pwreset_token" in params:
    _prt = params.get("pwreset_token")
    if _prt:
        st.session_state["_pwreset_token"] = _prt
        st.session_state["current_page"] = "pwreset_custom"

# 🔁 캠페인 가입 단계 — 새로고침해도 현재 가입 페이지 유지 (URL ?signup=...)
if "signup" in params:
    _sg = params.get("signup")
    _sg_map = {
        "select": "campaign_signup_select",
        "institution": "campaign_signup_institution",
        "parent": "campaign_signup_parent",
        "student": "campaign_signup_student",
    }
    if _sg in _sg_map:
        st.session_state["login_mode"] = "campaign"
        st.session_state["current_page"] = _sg_map[_sg]

# 🔐 비밀번호 재설정(복구) 모드 — 이메일 복구 링크가 sid+pwreset 으로 복귀시킴
if "pwreset" in params:
    st.session_state["_pw_recovery_mode"] = True

# 🔐 복구 링크의 해시(#type=recovery&refresh_token=...) 캡처 → sid+pwreset 쿼리파라미터로 변환
#    Supabase 복구 링크는 토큰을 URL 해시에 실어 보내는데 Streamlit 서버는 해시를 못 보므로,
#    최상위 창에서 해시를 읽어 기존 sid(세션복원) 메커니즘으로 넘긴다.
try:
    _a11y_components.html(
        """
        <script>
        (function(){
          try{
            var W = window.top || window;
            var h = W.location.hash || "";
            if(h.indexOf("type=recovery") >= 0){
              var qs = new URLSearchParams(h.replace(/^#/, ""));
              var rt = qs.get("refresh_token");
              if(rt){
                var base = W.location.origin + W.location.pathname;
                W.location.replace(base + "?sid=" + encodeURIComponent(rt) + "&pwreset=1");
              }
            }
          }catch(e){}
        })();
        </script>
        """,
        height=0,
    )
except Exception:
    pass

# ─── 🔐 세션 복원: sid (refresh_token) 사용 ───
# 옛 token 파라미터 호환 (기존 세션 마이그레이션) — 로그아웃 직후엔 skip
if "token" in params and st.session_state.user is None and "logged_out" not in params:
    try:
        token = params["token"]
        result = supabase.auth.get_user(token)
        if result.user:
            ud = supabase.table("users").select("*").eq("email", result.user.email).execute()
            if ud.data:
                st.session_state.user = ud.data[0]
                st.session_state.access_token = token
                this_month = date.today().strftime("%Y-%m")
                res = supabase.table("reports").select("id").eq("user_id", ud.data[0]["id"]).gte("created_at", f"{this_month}-01").execute()
                st.session_state.report_count = len(res.data)
                _new_user = ud.data[0]
                _new_role = (_new_user.get("role") or _new_user.get("role_v2") or "").lower()
                if _new_role == "agency_admin" or _new_user.get("is_tenant_admin"):
                    st.session_state.current_page = "agency_dashboard"
                else:
                    st.session_state.current_page = "home_landing"
        # 옛 token 정리
        if "token" in st.query_params:
            del st.query_params["token"]
    except Exception:
        if "token" in st.query_params:
            del st.query_params["token"]

# 신규 sid (refresh_token) 방식
# ⭐ URL에 ?logged_out=1로 직접 진입한 경우 (캠페인 헤더 logout button JS reload 경로 등)
if "logged_out" in params:
    # supabase + session_state + query_params 모두 정리
    try: _delete_app_session(params.get("sid"))  # 🔐 서버 세션 폐기(불투명ID 재사용 차단)
    except Exception: pass
    try: supabase.auth.sign_out()
    except Exception: pass
    try:
        for _k in list(st.session_state.keys()):
            try: del st.session_state[_k]
            except Exception: pass
    except Exception:
        pass
    try: st.query_params.clear()
    except Exception: pass
    # 캠페인 로그인 모드 default
    st.session_state["login_mode"] = "campaign"

if "sid" in params and st.session_state.user is None and "logged_out" not in params:
    try:
        _sid_raw = params["sid"]
        # 불투명ID → refresh_token 조회 (app_sessions에 없으면 raw 토큰으로 간주 = 기존/레거시 폴백)
        rt = _lookup_app_session(_sid_raw) or _sid_raw
        result = supabase.auth.refresh_session(rt)
        if result and result.session and result.user:
            ud = supabase.table("users").select("*").eq("email", result.user.email).execute()
            if ud.data:
                # 주말 차단 검사 (일반 사용자)
                from datetime import datetime as _dt_now
                _u = ud.data[0]
                _role = _u.get("role_v2", "user")
                _is_weekend = _dt_now.now().weekday() >= 5  # 5=토, 6=일
                # 본부/파트너/총판 admin은 주말에도 접속 가능
                _is_admin_role = (
                    _u.get("role") == "admin"
                    or _u.get("partner_role") == "partner_admin"
                    or _u.get("hq_position")
                    or _u.get("distributor_id")
                    or _u.get("is_tenant_admin")
                )
                if _role == "user" and _is_weekend and not _is_admin_role:
                    st.session_state.user = None
                    st.warning("📅 주말 보안 정책에 따라 일반 사용자는 토요일/일요일에 접속할 수 없습니다.")
                    if "sid" in st.query_params:
                        del st.query_params["sid"]
                else:
                    st.session_state.user = _u
                    st.session_state.access_token = result.session.access_token
                    st.session_state.refresh_token = result.session.refresh_token
                    # 🔐 sid 회전 — 새 불투명ID 발급(기존 ID 폐기). 캡처된 옛 ID 무효화
                    _set_session_param(result.session.refresh_token, result.user.email, old_sid=_sid_raw)
                    this_month = date.today().strftime("%Y-%m")
                    res = supabase.table("reports").select("id").eq("user_id", _u["id"]).gte("created_at", f"{this_month}-01").execute()
                    st.session_state.report_count = len(res.data)
                    # current_page는 사용자가 보던 페이지 보존하되, 기본값(home_landing)일 때는 role 기반 분기
                    _cur_page_sid = st.session_state.get("current_page", "home_landing")
                    if _cur_page_sid == "home_landing":
                        _sid_role = (_u.get("role") or _u.get("role_v2") or "").lower()
                        if _sid_role == "agency_admin" or _u.get("is_tenant_admin"):
                            st.session_state.current_page = "agency_dashboard"
    except Exception as _sess_err:
        # 세션 복원 실패 → sid 정리
        if "sid" in st.query_params:
            del st.query_params["sid"]

# ══════════════════════════════
# 조직 관리 헬퍼 함수
# ══════════════════════════════

def get_user_role(user):
    """역할 반환: superadmin > agency_admin > tenant_admin > group_leader > director > team_leader > user"""
    return user.get("role_v2") or ("admin" if user.get("role") == "admin" else "user")

def is_superadmin(user):
    return get_user_role(user) == "superadmin"

def is_agency_admin(user):
    """파트너관리자 여부 (Phase 7 보강 — 2026-05-16)

    원래: role_v2 == "agency_admin"만 인정
    Phase 7 추가:
        - partner_role == "partner_admin" (정다운/정희영/황철희)
        - role == "admin" + partner_id (role_v2 미설정 폴백)
        - is_tenant_admin (포유솔루션 정희영 케이스)
    """
    if not user:
        return False
    if get_user_role(user) == "agency_admin":
        return True
    if user.get("partner_role") == "partner_admin":
        return True
    if user.get("role") == "admin" and user.get("partner_id"):
        return True
    if user.get("is_tenant_admin"):
        return True
    return False

def is_tenant_admin(user):
    """업체관리자 여부"""
    return get_user_role(user) in ("tenant_admin", "agency_admin", "superadmin")

def is_director(user):
    return get_user_role(user) in (
        "superadmin", "agency_admin",
        "group_leader", "group_leader_2", "group_leader_3", "group_leader_4",
        "director", "director_2", "director_3", "director_4",
    )

def is_team_leader(user):
    return get_user_role(user) in (
        "superadmin", "agency_admin", "tenant_admin",
        "group_leader", "group_leader_2", "group_leader_3", "group_leader_4",
        "director", "director_2", "director_3", "director_4",
        "team_leader",
    )

# ═══════════════════════════════════════════════════════════════
# 🛡️ 페이지 진입 권한 가드 (5/5 보안 강화)
# ═══════════════════════════════════════════════════════════════
def guard_page(user, allowed_roles=None, allow_admins=True, redirect_to="home_landing"):
    """
    페이지 진입 시 권한 검사. 권한 없으면 메시지 + 홈으로 리다이렉트.
    allowed_roles: 명시적으로 허용할 role_v2 리스트 (None이면 관리자만)
    allow_admins: superadmin/agency_admin/tenant_admin 자동 허용
    반환: True (통과) / False (차단됨, 호출자가 return으로 종료해야 함)
    """
    if not user:
        st.error("🔒 로그인이 필요합니다.")
        st.session_state.current_page = "home_landing"
        st.rerun()
        return False

    _role = get_user_role(user)

    # 관리자 자동 통과
    if allow_admins and _role in ("superadmin", "agency_admin", "tenant_admin", "admin"):
        return True

    # Phase 7: 파트너 admin 케이스 (정다운/정희영/황철희)
    if allow_admins and (
        user.get("partner_role") == "partner_admin"
        or (user.get("role") == "admin" and user.get("partner_id"))
        or user.get("is_tenant_admin")
    ):
        return True

    # 명시적 허용 역할
    if allowed_roles and _role in allowed_roles:
        return True

    # 차단
    st.error("🚫 이 페이지에 접근할 권한이 없습니다.")
    st.caption(f"현재 권한: {role_label(_role)}")
    if st.button("🏠 홈으로 돌아가기", type="primary"):
        st.session_state.current_page = redirect_to
        st.rerun()
    return False


def can_view_report(user, report):
    """보고서 조회 권한 검사"""
    if not user or not report:
        return False
    _role = get_user_role(user)
    # 관리자 전체 조회 가능
    if _role in ("superadmin", "agency_admin", "tenant_admin", "admin"):
        return True
    # 본인 보고서
    if report.get("user_id") == user.get("id"):
        return True
    # 같은 팀 (team_leader)
    if _role == "team_leader" and user.get("team_id"):
        try:
            author = supabase.table("users").select("team_id").eq("id", report.get("user_id")).limit(1).execute().data or []
            if author and author[0].get("team_id") == user.get("team_id"):
                return True
        except Exception:
            pass
    # 같은 테넌트 (tenant_admin은 위에서 통과, 여기는 일반 사용자)
    return False


# ═══════════════════════════════════════════════════════════════
# 📋 다운로드 감사 로그 (5/5 추가) — 누가/언제/무엇을 추적
# ═══════════════════════════════════════════════════════════════
def log_download(user, resource_type, resource_label, file_format, file_name,
                 scope_description="", record_count=0,
                 scope_tenant_ids=None, scope_user_ids=None):
    """
    모든 다운로드를 download_logs 테이블에 기록.
    실패해도 다운로드 자체는 영향 없도록 try/except 처리.
    """
    try:
        if not user or not user.get("id"):
            return  # 비로그인은 기록 안함

        # Phase 4: user.partner_id 직접 사용 (DB 조회 불필요)
        _agency_id = user.get("partner_id") or user.get("agency_id")

        _log_data = {
            "user_id": user.get("id"),
            "user_name": user.get("name", ""),
            "user_email": user.get("email", ""),
            "user_role": get_user_role(user),
            "user_tenant_id": user.get("tenant_id"),
            "user_team_id": user.get("team_id"),
            "user_agency_id": _agency_id,
            "partner_id": _agency_id,  # Phase 4 듀얼 라이트
            "resource_type": resource_type,
            "resource_label": resource_label or "",
            "file_format": file_format or "",
            "file_name": file_name or "",
            "scope_description": scope_description or "",
            "record_count": int(record_count or 0),
            "scope_tenant_ids": scope_tenant_ids or [],
            "scope_user_ids": scope_user_ids or [],
        }
        supabase.table("download_logs").insert(_log_data).execute()
    except Exception as _e_log:
        # 로그 실패는 silent (다운로드 자체는 성공해야 함)
        try:
            print(f"[log_download] 실패: {_e_log}")
        except Exception:
            pass


def get_download_logs_for_user(viewer):
    """
    조회자(viewer)의 권한에 따라 download_logs를 필터링해서 반환.
    위계 원칙:
    - superadmin: 전체
    - agency_admin: 본인 + 본인이 담당하는 업체 사용자들의 다운로드
    - tenant_admin: 본인 + 본인 업체 사용자들의 다운로드
    - team_leader: 본인 + 본인 팀원들의 다운로드
    - 일반 사용자: 본인 것만
    """
    if not viewer:
        return []
    _role = get_user_role(viewer)
    try:
        _q = supabase.table("download_logs").select("*").order("downloaded_at", desc=True).limit(500)

        if _role in ("superadmin", "admin"):
            return _q.execute().data or []

        if is_agency_admin(viewer):
            # 본인 + 담당 업체들의 사용자들
            # Phase 4: viewer.partner_id로 partner_customers 조회
            _viewer_partner_id = viewer.get("partner_id") or viewer.get("agency_id")
            _agency_tids = [pc["tenant_id"] for pc in (supabase.table("partner_customers").select("tenant_id").eq("partner_id", _viewer_partner_id).execute().data or [])] if _viewer_partner_id else []
            _scope_uids = [u["id"] for u in (supabase.table("users").select("id").in_("tenant_id", _agency_tids).execute().data or [])] if _agency_tids else []
            _scope_uids.append(viewer["id"])
            return _q.in_("user_id", list(set(_scope_uids))).execute().data or []

        if is_tenant_admin(viewer):
            # 본인 업체 사용자들
            _scope_uids = [u["id"] for u in (supabase.table("users").select("id").eq("tenant_id", viewer.get("tenant_id","")).execute().data or [])]
            return _q.in_("user_id", _scope_uids).execute().data or [] if _scope_uids else []

        if _role == "team_leader":
            # 자기 팀원들
            _scope_uids = [u["id"] for u in (supabase.table("users").select("id").eq("team_id", viewer.get("team_id","")).execute().data or [])]
            return _q.in_("user_id", _scope_uids).execute().data or [] if _scope_uids else []

        # 일반 사용자: 본인 것만
        return _q.eq("user_id", viewer["id"]).execute().data or []
    except Exception:
        return []


def render_excel_download(label, rows, *, resource_type, resource_label,
                          file_basename, user, scope_description="",
                          scope_tenant_ids=None, scope_user_ids=None,
                          key=None, sheet_name="Sheet1"):
    """DataFrame(rows)을 엑셀로 내려받는 버튼 + 감사로그(log_download) 일괄 처리.

    엑셀 출력 에픽(2026-05-18) 공통 헬퍼 — 영업 파이프라인·파트너 명단·
    그룹별 사용자 등 모든 엑셀 출력을 이 함수 하나로 통일한다.

    rows: list[dict] 또는 pandas.DataFrame
    """
    import io as _io
    try:
        _df = rows if hasattr(rows, "to_excel") else pd.DataFrame(rows or [])
    except Exception as _e:
        st.caption(f"엑셀 데이터 준비 실패: {str(_e)[:80]}")
        return
    if _df is None or len(_df) == 0:
        st.caption(f"📭 {resource_label} — 내보낼 데이터가 없습니다.")
        return
    _today = date.today().strftime("%Y%m%d")
    _fname = f"DragonEyes_{file_basename}_{_today}.xlsx"
    try:
        _buf = _io.BytesIO()
        with pd.ExcelWriter(_buf, engine="openpyxl") as _wr:
            _df.to_excel(_wr, index=False, sheet_name=str(sheet_name)[:31])
        _buf.seek(0)
        if st.download_button(
            label,
            data=_buf.getvalue(),
            file_name=_fname,
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            use_container_width=True,
            key=key or f"xlsx_dl_{resource_type}",
        ):
            log_download(
                user=user,
                resource_type=resource_type,
                resource_label=resource_label,
                file_format="xlsx",
                file_name=_fname,
                scope_description=scope_description,
                record_count=len(_df),
                scope_tenant_ids=scope_tenant_ids,
                scope_user_ids=scope_user_ids,
            )
    except Exception as _e:
        st.caption(f"엑셀 생성 실패: {str(_e)[:80]}")


# ── 파트너관리자 헬퍼 함수 ──
@st.cache_data(ttl=60, show_spinner=False)
def get_agency_tenants(agency_user_id):
    """Phase 4: 파트너가 담당하는 업체 목록 (partners + partner_customers 사용)"""
    try:
        # user_id로 partner 찾기 (해당 user의 partner_id로 partners 조회)
        u = supabase.table("users").select("partner_id, agency_id").eq("id", agency_user_id).execute()
        if not u.data:
            return []
        partner_id = u.data[0].get("partner_id") or u.data[0].get("agency_id")
        if not partner_id:
            return []
        pc = supabase.table("partner_customers").select("tenant_id").eq("partner_id", partner_id).execute()
        if not pc.data:
            return []
        tenant_ids = [x["tenant_id"] for x in pc.data]
        tenants = supabase.table("tenants").select("*").in_("id", tenant_ids).execute()
        return tenants.data or []
    except:
        return []

@st.cache_data(ttl=60, show_spinner=False)
def get_tenant_users(tenant_id):
    """특정 업체의 사용자 목록"""
    try:
        return supabase.table("users").select("*").eq("tenant_id", tenant_id).execute().data or []
    except:
        return []

@st.cache_data(ttl=60, show_spinner=False)
def get_all_tenants():
    """전체 업체 목록"""
    try:
        return supabase.table("tenants").select("*").order("name").execute().data or []
    except:
        return []

@st.cache_data(ttl=60, show_spinner=False)
def _pay_label(pt):
    """납입 종류 한글 라벨"""
    return {"monthly":"월납", "annual":"연납", "lump_sum":"일시납"}.get(pt or "", "-")

def get_all_agencies():
    """Phase 4: 전체 파트너 목록 (partners 테이블 사용, 레거시 함수명 유지)"""
    try:
        return supabase.table("partners").select("*").execute().data or []
    except:
        return []


# ════════════════════════════════════════════════════════════════
# PO 양식(.xlsx) 파서 (5/14 추가, AI 파서 Step 2)
# DragonEyes 표준 PO 양식 v2 (5종: Tier1/2/3-100/200/500) 인식
# ════════════════════════════════════════════════════════════════
def parse_po_xlsx(uploaded_file):
    """
    PO 양식(.xlsx)을 파싱하여 신청서 데이터로 변환
    
    Returns dict with:
        - tier_detected, po_no, date
        - agency (TO 대리점), customer (FROM 고객사)
        - regulatory_authority, business_field, payment_terms
        - items (라이선스 발주 명세)
        - total_amount
        - users (관리자 + 일반 사용자 리스트)
        - errors, warnings
        - user_count
    """
    import openpyxl
    from io import BytesIO
    
    result = {
        "tier_detected": "",
        "po_no": "", "date": "",
        "agency": {}, "customer": {},
        "regulatory_authority": "", "business_field": "",
        "payment_terms": "",
        "items": [],
        "total_amount": 0,
        "users": [],
        "errors": [],
        "warnings": [],
        "user_count": 0,
    }
    
    try:
        # 파일 로드
        uploaded_file.seek(0)
        wb = openpyxl.load_workbook(BytesIO(uploaded_file.read()), data_only=True)
        ws = wb.active  # 첫 번째 시트
        
        # 시트명 검증 (양식 인식)
        if "DragonEyes" not in (ws.title or "") and "라이선스" not in (ws.title or ""):
            result["warnings"].append(f"시트명이 표준 양식과 다릅니다: '{ws.title}'")
        
        # ─── 1. PO NO, DATE ───
        result["po_no"] = str(ws["C4"].value or "").strip()
        date_val = ws["G4"].value
        if date_val:
            result["date"] = str(date_val)[:10] if hasattr(date_val, "year") else str(date_val).strip()
        
        # ─── 2. ① TO 대리점 정보 ───
        result["agency"] = {
            "name": str(ws["C6"].value or "").strip(),
            "address": str(ws["C7"].value or "").strip(),
            "ceo": str(ws["C8"].value or "").strip(),
            "biz_number": str(ws["C9"].value or "").strip(),
            "manager": str(ws["C10"].value or "").strip(),
            "phone": str(ws["C11"].value or "").strip(),
            "email": str(ws["C12"].value or "").strip(),
        }
        
        # ─── 3. ② FROM 고객사 정보 ───
        result["customer"] = {
            "name": str(ws["G6"].value or "").strip(),
            "address": str(ws["G7"].value or "").strip(),
            "ceo": str(ws["G8"].value or "").strip(),
            "biz_number": str(ws["G9"].value or "").strip(),
            "manager": str(ws["G10"].value or "").strip(),
            "phone": str(ws["G11"].value or "").strip(),
            "email": str(ws["G12"].value or "").strip(),
        }
        
        # ─── 4. 관할 기관 + 사업 분야 + 결제 ───
        result["regulatory_authority"] = str(ws["C13"].value or "").strip()
        result["business_field"] = str(ws["G13"].value or "").strip()
        result["payment_terms"] = str(ws["C14"].value or "").strip()
        
        # 예시 텍스트 필터링 (양식의 안내 텍스트는 제외)
        for key in ["regulatory_authority", "business_field", "payment_terms"]:
            val = result[key]
            if val.startswith("예:") or "예시" in val or val.startswith("일시불 /"):
                result[key] = ""
        
        # ─── 5. 라이선스 발주 명세 (Row 19~21) — Phase 6 v2/v3 호환 ───
        # Phase 6 (5/14 PM): 단가/수량/기간 구조로 업그레이드
        #   v2 양식: G=시작일, H=종료일, I=단가, J=금액
        #   v3 양식: G=단가,    H=수량,    I=기간(개월), J=금액
        # 자동 인식: G가 날짜형이면 v2, 숫자(작은 값)면 v3
        
        import datetime as _dt_mod
        
        def _excel_date_to_str(val):
            """Excel 직렬 날짜/datetime → YYYY-MM-DD"""
            if val is None or val == "":
                return ""
            if isinstance(val, _dt_mod.datetime):
                return val.strftime("%Y-%m-%d")
            if isinstance(val, _dt_mod.date):
                return val.strftime("%Y-%m-%d")
            if isinstance(val, (int, float)) and val > 30000:
                try:
                    dt = _dt_mod.datetime(1899, 12, 30) + _dt_mod.timedelta(days=int(val))
                    return dt.strftime("%Y-%m-%d")
                except:
                    pass
            return str(val)[:10]
        
        def _to_int_safe(val):
            """안전한 int 변환"""
            if val is None or val == "":
                return 0
            try:
                if isinstance(val, str):
                    val = val.replace(",", "").replace("원", "").strip()
                return int(float(val))
            except (ValueError, TypeError):
                return 0
        
        def _looks_like_date(val):
            """날짜 셀처럼 보이는지 — v2/v3 자동 판정용
            v2 양식: G=시작일(datetime), v3 양식: G=단가(int)
            500000원 같은 큰 숫자가 날짜로 오인되는 버그 수정 (5/14)
            → datetime 객체이거나, 'YYYY-MM-DD' 형식 문자열일 때만 날짜로 판정
            → int/float은 모두 숫자(단가)로 처리 → v3 모드"""
            if isinstance(val, (_dt_mod.datetime, _dt_mod.date)):
                return True
            if isinstance(val, str):
                # "2026-05-15" 형식만 날짜로 인식 (10자, '-' 2개)
                return len(val) >= 8 and val.count("-") >= 2
            # int/float은 단가로 처리 (v3 모드)
            return False
        
        def _calc_months(start_str, end_str):
            """YYYY-MM-DD 두 날짜 사이의 개월 수"""
            if not start_str or not end_str:
                return 0
            try:
                s = _dt_mod.datetime.strptime(start_str, "%Y-%m-%d")
                e = _dt_mod.datetime.strptime(end_str, "%Y-%m-%d")
                months = (e.year - s.year) * 12 + (e.month - s.month)
                return max(months, 1)
            except:
                return 0
        
        for row_idx in [19, 20, 21]:
            description = str(ws[f"C{row_idx}"].value or "").strip()
            grade_raw = str(ws[f"F{row_idx}"].value or "").strip()
            # Phase 6 Step 2: B 컬럼(ITEM) 거래유형 인식
            item_b = str(ws[f"B{row_idx}"].value or "").strip()
            if not description and not grade_raw:
                continue
            
            # 등급 매핑
            grade = "standard"
            if "Pro" in grade_raw or "프로" in grade_raw or "🥇" in grade_raw:
                grade = "pro"
            elif "Enterprise" in grade_raw or "엔터" in grade_raw or "💎" in grade_raw:
                grade = "enterprise"
            elif "Standard" in grade_raw or "스탠다드" in grade_raw or "🥈" in grade_raw:
                grade = "standard"
            
            # Phase 6 Step 2: ITEM 거래유형 매핑 (ARR 추적용)
            # 좋아요님 5/14 결정: 신규/갱신/추가/다운그레이드
            transaction_type = "new"  # 기본값
            if "갱신" in item_b or "Renewal" in item_b or "🔄" in item_b:
                transaction_type = "renewal"
            elif "추가" in item_b or "Add-on" in item_b or "Addon" in item_b or "➕" in item_b:
                transaction_type = "addon"
            elif "다운그레이드" in item_b or "Downgrade" in item_b or "⬇️" in item_b:
                transaction_type = "downgrade"
            elif "신규" in item_b or "New" in item_b or "🆕" in item_b:
                transaction_type = "new"
            # 숫자만 있거나(v2 호환) 빈 값이면 "new"로 처리
            
            # Phase 6 Step 2: 품목 카테고리 매핑 (catalog 매핑)
            item_category = "license"  # 기본값
            if "컨설팅" in description or "Consulting" in description:
                item_category = "consulting"
            elif "셋업" in description or "Setup" in description or "셋업 비용" in description:
                item_category = "setup"
            elif "교육" in description or "Training" in description:
                item_category = "training"
            elif "라이선스" in description or "License" in description or "DragonEyes" in description:
                item_category = "license"
            elif "기타" in description:
                item_category = "other"
            
            # G/H/I 셀 값
            g_val = ws[f"G{row_idx}"].value
            h_val = ws[f"H{row_idx}"].value
            i_val = ws[f"I{row_idx}"].value
            j_val = ws[f"J{row_idx}"].value
            
            # v2/v3 자동 인식: G가 날짜처럼 보이면 v2
            is_v2 = _looks_like_date(g_val)
            
            if is_v2:
                # v2: G=시작일, H=종료일, I=단가, J=금액
                start_date = _excel_date_to_str(g_val)
                end_date = _excel_date_to_str(h_val)
                unit_price = _to_int_safe(i_val)
                amount = _to_int_safe(j_val)
                # v2에서 수량/기간 추정
                quantity = result.get("user_count", 0) or 1  # 사용자 수로 추정
                period_months = _calc_months(start_date, end_date) or 1
                form_version = "v2"
            else:
                # v3: G=단가, H=수량, I=기간(개월), J=금액
                unit_price = _to_int_safe(g_val)
                quantity = _to_int_safe(h_val) or 1
                period_months = _to_int_safe(i_val) or 1
                amount = _to_int_safe(j_val) or (unit_price * quantity * period_months)
                start_date = ""
                end_date = ""
                form_version = "v3"
            
            result["items"].append({
                "description": description,
                "grade": grade,
                # Phase 6 Step 2: ITEM 거래유형 + 카테고리 (ARR 추적용)
                "transaction_type": transaction_type,
                "item_category": item_category,
                "unit_price": unit_price,
                "quantity": quantity,
                "period_months": period_months,
                "amount": amount,
                # v2 호환 (있으면 보관, v3는 빈 문자열)
                "start_date": start_date,
                "end_date": end_date,
                # 양식 버전 표시
                "form_version": form_version,
            })
        
        # ─── 6. 총액 ───
        try:
            result["total_amount"] = _to_int_safe(ws["J23"].value)
        except:
            result["total_amount"] = 0
        if not result["total_amount"]:
            result["total_amount"] = sum(item["amount"] for item in result["items"])
        
        # 양식 버전 통합 (모든 line이 같은 버전이면 통일)
        if result["items"]:
            _versions = set(it.get("form_version") for it in result["items"])
            if len(_versions) == 1:
                result["form_version"] = list(_versions)[0]
            else:
                result["form_version"] = "mixed"
        
        # ─── 7. 사용자 지정 (Row 28: ⭐ 관리자, Row 29~: 일반 사용자) ───
        # Tier별 사용자 수 자동 감지: Row 28부터 빈 행 만날 때까지 또는 시그너처 영역 전까지
        max_row = ws.max_row
        users_collected = []
        
        for row_idx in range(28, min(max_row + 1, 600)):  # 최대 500명 + 여유
            # B열: 구분 (⭐ 관리자 / 사용자 N)
            role_cell = str(ws[f"B{row_idx}"].value or "").strip()
            
            # 시그너처 영역 도달 시 종료
            if "서명" in role_cell or "Signatures" in role_cell:
                break
            
            # 빈 행 또는 사용자 영역 끝
            if not role_cell:
                # 다음 5행 중 데이터 있으면 계속, 없으면 종료
                has_more = False
                for check_row in range(row_idx + 1, min(row_idx + 6, max_row + 1)):
                    if str(ws[f"B{check_row}"].value or "").strip():
                        has_more = True
                        break
                if not has_more:
                    break
                continue
            
            # 사용자 데이터 추출
            name = str(ws[f"C{row_idx}"].value or "").strip()
            if not name:
                continue  # 이름 없으면 빈 행으로 간주
            
            # 역할 결정
            user_role = "admin" if "관리자" in role_cell or "⭐" in role_cell else "user"
            
            users_collected.append({
                "role": user_role,
                "name": name,
                "email": str(ws[f"D{row_idx}"].value or "").strip(),
                "phone": str(ws[f"E{row_idx}"].value or "").strip(),
                "guardian_name": str(ws[f"F{row_idx}"].value or "").strip(),
                "guardian_phone": str(ws[f"G{row_idx}"].value or "").strip(),
                "org": str(ws[f"H{row_idx}"].value or "").strip(),
            })
        
        result["users"] = users_collected
        result["user_count"] = len(users_collected)
        
        # ─── 8. Tier 자동 감지 (사용자 수 기준) ───
        count = result["user_count"]
        if count <= 10:
            result["tier_detected"] = "Tier 1 (최대 10명)"
        elif count <= 50:
            result["tier_detected"] = "Tier 2 (최대 50명)"
        elif count <= 100:
            result["tier_detected"] = "Tier 3-100"
        elif count <= 200:
            result["tier_detected"] = "Tier 3-200"
        elif count <= 500:
            result["tier_detected"] = "Tier 3-500"
        else:
            result["tier_detected"] = f"미지정 ({count}명)"
        
        # ─── 9. 검증 ───
        if not result["customer"]["name"]:
            result["errors"].append("고객사명(② FROM)이 비어있습니다.")
        if not result["users"]:
            result["errors"].append("사용자 정보(④)가 비어있습니다.")
        else:
            # 관리자 1명 필수
            admin_count = sum(1 for u in result["users"] if u["role"] == "admin")
            if admin_count == 0:
                result["errors"].append("관리자가 지정되지 않았습니다. ④ 표 첫 행에 ⭐ 관리자를 입력해주세요.")
            elif admin_count > 1:
                result["warnings"].append(f"관리자가 {admin_count}명 지정되었습니다. (첫 번째 관리자가 대표로 등록됩니다)")
        
        # 발주 수량 vs 사용자 수 일치 확인
        if result["items"] and result["user_count"] > 0:
            # 발주 명세의 unit_price 합산 vs 사용자 수 비교는 단가 일치 시에만 가능
            # 일단 사용자 수 표시
            pass
        
    except Exception as e:
        result["errors"].append(f"파일 파싱 오류: {str(e)[:200]}")
    
    return result


def send_notification(sent_by_id, target_type, target_id, channel, subject, body):
    """알림 발송 + 실제 이메일 발송 (Resend)"""
    email_sent = False
    recipient_email = None

    try:
        # 수신자 이메일 조회
        if target_id and target_type == "individual":
            user_res = supabase.table("users").select("email,name").eq("id", str(target_id)).execute()
            if user_res.data:
                recipient_email = user_res.data[0].get("email", "")

        # Resend로 실제 이메일 발송
        if recipient_email and RESEND_API_KEY and channel in ("email", "both"):
            try:
                resend.api_key = RESEND_API_KEY
                resend.Emails.send({
                    "from": "AI agent_dragoneyes <dragoneyes@dragoneyes.co.kr>",
                    "to": [recipient_email],
                    "subject": subject,
                    "html": f"""
                    <div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;">
                        <div style="background:linear-gradient(135deg,#0f3460,#16213e);padding:20px;border-radius:8px;margin-bottom:20px;">
                            <h2 style="color:white;margin:0;">🐉 DragonEyes 모니터링</h2>
                        </div>
                        <div style="background:#f8fafc;padding:20px;border-radius:8px;border:1px solid #e2e8f0;">
                            <h3 style="color:#1e293b;">{subject}</h3>
                            <div style="color:#475569;line-height:1.8;white-space:pre-wrap;">{body}</div>
                        </div>
                        <p style="color:#94a3b8;font-size:0.8rem;margin-top:16px;text-align:center;">
                            본 메일은 DragonEyes 모니터링 시스템에서 자동 발송되었습니다.
                        </p>
                    </div>
                    """,
                })
                email_sent = True
            except Exception as e:
                email_sent = False
                # v2026.04.26 — 이메일 발송 에러 로깅
                try:
                    st.warning(f"⚠️ 이메일 발송 실패: {str(e)[:200]}")
                except:
                    pass

        # DB에 발송 기록 저장
        supabase.table("notifications").insert({
            "sent_by": sent_by_id,
            "target_type": target_type,
            "target_id": str(target_id) if target_id else "all",
            "channel": channel,
            "subject": subject,
            "body": body,
            "status": "sent" if email_sent else "pending",
        }).execute()
        return True
    except:
        return False

def can_approve(user, target_user=None):
    role = get_user_role(user)
    if role in ("superadmin", "group_leader", "director"):
        return True
    if role == "team_leader":
        if target_user is None:
            return True
        return target_user.get("team_id") == user.get("team_id")
    return False

@st.cache_data(ttl=30, show_spinner=False)
def get_all_users():
    try:
        return supabase.table("users").select("*").execute().data or []
    except:
        return []

def check_user_terms(user):
    """사용자 동의 여부 확인"""
    return user.get("terms_agreed", False) and user.get("terms_version") == TERMS_VERSION

def save_user_consent(user_id, name, email):
    """사용자 동의 저장"""
    try:
        supabase.table("user_consents").insert({
            "user_id": user_id,
            "consent_version": TERMS_VERSION,
            "name": name,
            "email": email,
        }).execute()
        supabase.table("users").update({
            "terms_agreed": True,
            "terms_agreed_at": datetime.now().isoformat(),
            "terms_version": TERMS_VERSION,
        }).eq("id", user_id).execute()
        return True
    except Exception as e:
        return False

@st.cache_data(ttl=60, show_spinner=False)
def get_all_teams():
    try:
        return supabase.table("teams").select("*").execute().data or []
    except:
        return []

@st.cache_data(ttl=60, show_spinner=False)
def get_team_members(team_id):
    try:
        return supabase.table("users").select("*").eq("team_id", team_id).execute().data or []
    except:
        return []

def get_unread_announcements(user_id):
    try:
        all_ann = supabase.table("announcements").select("id").eq("is_deleted", False).execute().data or []
        read_ids = [r["announcement_id"] for r in (supabase.table("announcement_reads").select("announcement_id").eq("user_id", user_id).execute().data or [])]
        return [a for a in all_ann if a["id"] not in read_ids]
    except:
        return []


# ============================================================
# Phase 7L Part 4: 영업 기회 → 계약 생성 헬퍼 함수
# 작성일: 2026-05-17
# 위치: save_user_consent 함수 다음에 자동 삽입
# ============================================================

def _create_contract_from_opportunity(opp, user, tier_code, seat_count,
                                       start_date, end_date, duration_months,
                                       monthly_amount, total_amount):
    """영업 기회 → customers + contracts + licenses 일괄 생성"""
    try:
        # license_tiers 마스터 조회
        tier_resp = supabase.table("license_tiers") \
            .select("*").eq("tier_code", tier_code).eq("is_active", True) \
            .single().execute()
        tier = tier_resp.data
        if not tier:
            return {"success": False, "error": f"라이선스 등급 {tier_code} 없음"}

        multiplier = tier.get("waiting_group_multiplier")
        waiting_group_limit = (seat_count * multiplier) if multiplier else 0

        # 1. customers UPSERT (사업자번호 매칭)
        biz_no = opp.get("customer_business_no") or opp.get("customer_business_reg")
        customer_id = None
        customer_no = None

        if biz_no:
            existing = supabase.table("customers") \
                .select("id, customer_no").eq("business_number", biz_no) \
                .limit(1).execute().data
            if existing:
                customer_id = existing[0]["id"]
                customer_no = existing[0]["customer_no"]

        if not customer_id:
            new_customer = {
                "name": opp.get("customer_name", "(이름 없음)"),
                "business_number": biz_no,
                "representative_name": opp.get("customer_ceo_name"),
                "address": opp.get("customer_address"),
                "phone": opp.get("customer_contact_phone"),
                "email": opp.get("customer_contact_email"),
                "contact_person_name": opp.get("customer_contact_name"),
                "contact_person_position": opp.get("customer_contact_title"),
                "contact_person_phone": opp.get("customer_contact_phone"),
                "contact_person_email": opp.get("customer_contact_email"),
                "industry": opp.get("business_field"),
                "customer_status": "active",
                "onboarded_at": datetime.now().isoformat(),
            }
            customer_resp = supabase.table("customers").insert(new_customer).execute()
            if not customer_resp.data:
                return {"success": False, "error": "고객사 생성 실패"}
            customer_id = customer_resp.data[0]["id"]
            customer_no = customer_resp.data[0].get("customer_no")

        # 2. contracts INSERT
        new_contract = {
            "opportunity_id": opp["id"],
            "related_customer_id": customer_id,
            "tier_code": tier_code,
            "seat_count": seat_count,
            "waiting_group_count": waiting_group_limit,
            "contract_type": "license",
            "contract_amount": total_amount,
            "contract_currency": "KRW",
            "contract_status": "active",
            "contract_effective_from": start_date.isoformat() if hasattr(start_date, 'isoformat') else str(start_date),
            "contract_effective_to": end_date.isoformat() if hasattr(end_date, 'isoformat') else str(end_date),
            "contract_signed_date": datetime.now().date().isoformat(),
            "notes": f"영업기회 자동생성: {tier['tier_name_ko']} {seat_count}석 {duration_months}개월",
        }
        contract_resp = supabase.table("contracts").insert(new_contract).execute()
        if not contract_resp.data:
            return {"success": False, "error": "계약 생성 실패"}
        contract_id = contract_resp.data[0]["id"]
        contract_no = contract_resp.data[0].get("contract_no")

        # 3. licenses 일괄 INSERT (실제 좌석만, Waiting은 한도만 저장)
        license_rows = []
        for i in range(1, seat_count + 1):
            license_rows.append({
                "contract_id": contract_id,
                "tier_code": tier_code,
                "is_waiting": False,
            })

        BATCH_SIZE = 50
        license_count = 0
        for batch_start in range(0, len(license_rows), BATCH_SIZE):
            batch = license_rows[batch_start:batch_start + BATCH_SIZE]
            lic_resp = supabase.table("licenses").insert(batch).execute()
            if lic_resp.data:
                license_count += len(lic_resp.data)

        # 4. opportunities.status → 'contracted'
        supabase.table("opportunities") \
            .update({
                "status": "contracted",
                "closed_at": datetime.now().isoformat(),
                "updated_at": datetime.now().isoformat(),
            }) \
            .eq("id", opp["id"]).execute()

        # 5. 영업 활동 로그 기록
        try:
            supabase.table("opportunity_activities").insert({
                "opportunity_id": opp["id"],
                "activity_type": "contract_sent",
                "title": f"📝 계약 생성 완료 ({contract_no})",
                "content": f"{tier['tier_name_ko']} {seat_count}석, {duration_months}개월, 총 {total_amount:,}원. 고객사: {customer_no}",
                "activity_date": datetime.now().date().isoformat(),
                "created_by_name": user.get("name", "시스템"),
            }).execute()
        except Exception as e:
            print(f"[WARN] 활동 로그 실패: {e}")

        return {
            "success": True,
            "customer_id": customer_id,
            "customer_no": customer_no,
            "contract_id": contract_id,
            "contract_no": contract_no,
            "license_count": license_count,
            "waiting_group_limit": waiting_group_limit,
        }
    except Exception as e:
        import traceback
        traceback.print_exc()
        return {"success": False, "error": str(e)}


def _render_contract_creation_form(opp, user):
    """영업 기회에서 계약 생성 폼 렌더링"""
    try:
        tiers_resp = supabase.table("license_tiers") \
            .select("*").eq("is_active", True).order("display_order").execute()
        tiers = tiers_resp.data
    except Exception as e:
        st.error(f"❌ 라이선스 등급 정보를 불러올 수 없습니다: {e}")
        return

    if not tiers:
        st.warning("⚠️ 등록된 라이선스 등급이 없습니다.")
        return

    tier_codes = [t["tier_code"] for t in tiers]
    tier_options = {t["tier_code"]: t for t in tiers}
    tier_labels = [
        f"{t['tier_name_ko']} ({int(t['monthly_price_per_seat']):,}원/seat, {t['usage_type']})"
        for t in tiers
    ]

    opp_tier_raw = (opp.get("license_tier") or "Standard").strip()
    opp_tier_upper = opp_tier_raw.upper()
    default_idx = tier_codes.index(opp_tier_upper) if opp_tier_upper in tier_codes else 0

    opp_id = opp["id"]

    # 폼 입력
    col1, col2 = st.columns(2)
    with col1:
        tier_idx = st.selectbox(
            "📦 라이선스 등급",
            range(len(tier_labels)),
            format_func=lambda i: tier_labels[i],
            index=default_idx,
            key=f"contract_tier_{opp_id}"
        )
        selected_tier_code = tier_codes[tier_idx]
        selected_tier = tier_options[selected_tier_code]

        default_seats = int(opp.get("expected_seats") or 1)
        seat_count = st.number_input(
            "💺 좌석 수",
            min_value=1, max_value=10000,
            value=default_seats, step=1,
            key=f"contract_seats_{opp_id}"
        )

    with col2:
        from datetime import date as _date, timedelta as _td
        start_date = st.date_input(
            "📅 계약 시작일",
            value=_date.today(),
            key=f"contract_start_{opp_id}"
        )
        duration_months = st.number_input(
            "⏱️ 계약 기간 (개월)",
            min_value=1, max_value=60,
            value=12, step=1,
            key=f"contract_duration_{opp_id}",
            help="기본 12개월(1년). 필요 시 개월 단위 수정 가능"
        )
        end_date = start_date + _td(days=duration_months * 30)
        st.caption(f"📅 만료일: **{end_date.strftime('%Y-%m-%d')}** (시작일 + {duration_months}개월)")

    # 자동 계산
    monthly_price = int(selected_tier["monthly_price_per_seat"])
    monthly_total = monthly_price * seat_count
    total_amount = monthly_total * duration_months

    multiplier = selected_tier.get("waiting_group_multiplier")
    if multiplier:
        waiting_slots = seat_count * multiplier
        waiting_info = f"+ Waiting Group 한도 <strong>{waiting_slots}석</strong> ({seat_count}석 × {multiplier}배)"
        usage_badge = '<span style="background:#3b82f6;color:white;padding:2px 8px;border-radius:4px;font-size:0.75rem;">Concurrent</span>'
    else:
        waiting_info = "Named license — Waiting Group 없음 (지정 사용자 전용)"
        usage_badge = '<span style="background:#8b5cf6;color:white;padding:2px 8px;border-radius:4px;font-size:0.75rem;">Named</span>'

    transfer_rule = "본부 승인 필요" if selected_tier.get("transfer_approval_required") else "자유 양도"

    st.markdown(f"""
    <div style="background:linear-gradient(135deg,#f1f5f9,#e2e8f0);padding:18px;border-radius:10px;margin:12px 0;border-left:4px solid #3b82f6;">
        <p style="margin:0 0 8px 0;font-size:0.95rem;color:#0f172a;"><strong>📊 자동 계산</strong> {usage_badge}</p>
        <p style="margin:6px 0;"><strong>등급</strong>: {selected_tier['tier_name_ko']}</p>
        <p style="margin:6px 0;"><strong>월 단가</strong>: {monthly_price:,}원/seat × {seat_count}석 = <strong>{monthly_total:,}원/월</strong></p>
        <p style="margin:6px 0;"><strong>총 계약 금액</strong>: <span style="color:#dc2626;font-size:1.15rem;font-weight:bold;">{total_amount:,}원</span> ({duration_months}개월)</p>
        <p style="margin:6px 0;font-size:0.88rem;color:#475569;">{waiting_info}</p>
        <p style="margin:6px 0;font-size:0.88rem;color:#475569;">양도 정책: <strong>{transfer_rule}</strong></p>
    </div>
    """, unsafe_allow_html=True)

    # 2단계 확인 버튼
    confirm_key = f"contract_confirm_{opp_id}"
    if confirm_key not in st.session_state:
        st.session_state[confirm_key] = False

    if not st.session_state[confirm_key]:
        if st.button("✅ 계약 생성", type="primary", use_container_width=True,
                     key=f"create_contract_btn_{opp_id}"):
            st.session_state[confirm_key] = True
            st.rerun()
    else:
        st.warning(f"⚠️ 정말 생성하시겠습니까? 고객사 1건, 계약 1건, 라이선스 {seat_count}건이 생성됩니다.")
        col_y, col_n = st.columns(2)
        with col_y:
            if st.button("✅ 네, 생성합니다", type="primary", use_container_width=True,
                         key=f"yes_create_{opp_id}"):
                with st.spinner("계약 생성 중..."):
                    result = _create_contract_from_opportunity(
                        opp=opp, user=user,
                        tier_code=selected_tier_code,
                        seat_count=seat_count,
                        start_date=start_date,
                        end_date=end_date,
                        duration_months=duration_months,
                        monthly_amount=monthly_total,
                        total_amount=total_amount,
                    )
                if result["success"]:
                    st.session_state[confirm_key] = False
                    st.success(f"""🎉 계약 생성 완료!
- 고객사 번호: **{result['customer_no']}**
- 계약 번호: **{result['contract_no']}**
- 라이선스 발급: **{result['license_count']}건**
- Waiting Group 한도: **{result['waiting_group_limit']}석**""")
                    st.balloons()
                    import time as _time
                    _time.sleep(2)
                    st.rerun()
                else:
                    st.error(f"❌ 계약 생성 실패: {result['error']}")
                    st.session_state[confirm_key] = False
        with col_n:
            if st.button("❌ 취소", use_container_width=True, key=f"cancel_create_{opp_id}"):
                st.session_state[confirm_key] = False
                st.rerun()

