@st.cache_data(ttl=600, show_spinner=False)
def neis_search_schools(query=None, region_code=None, type_filter=None, limit=50):
    """NEIS Open API로 학교 검색.

    Args:
        query: 학교명 부분 일치 (선택 — 없으면 region_code 필수)
        region_code: ATPT_OFCDC_SC_CODE (B10/C10 등) — 시·도별 검색
        type_filter: 'elementary' / 'middle' / 'high' / 'special' / None(전체)
        limit: 최대 결과 수

    Returns:
        list[dict]: [{name, code, neis_id, type, region, district, ...}]
    """
    # 검색 조건 — 학교명 또는 지역 코드 중 하나 이상 필요
    if not query and not region_code:
        return []
    if query and len(query.strip()) < 2:
        return []
    key = os.getenv("NEIS_API_KEY", "")
    url = "https://open.neis.go.kr/hub/schoolInfo"
    params = {
        "Type": "json",
        "pIndex": 1,
        "pSize": min(max(limit, 10), 1000),
    }
    if query:
        params["SCHUL_NM"] = query.strip()
    if region_code:
        params["ATPT_OFCDC_SC_CODE"] = region_code
    if key:
        params["KEY"] = key
    try:
        r = requests.get(url, params=params, timeout=8)
        r.raise_for_status()
        data = r.json()
        info = data.get("schoolInfo", [])
        if len(info) < 2:
            return []
        rows = info[1].get("row", []) or []
    except Exception:
        return []

    _type_map = {
        "초등학교": "elementary",
        "중학교":   "middle",
        "고등학교": "high",
        "특수학교": "special",
        "각종학교": "other",
    }
    results = []
    for row in rows:
        kind = row.get("SCHUL_KND_SC_NM", "")
        mapped_type = _type_map.get(kind, "other")
        if type_filter and mapped_type != type_filter:
            continue
        results.append({
            "name":          row.get("SCHUL_NM", ""),
            "code":          row.get("SD_SCHUL_CODE", ""),
            "neis_id":       row.get("SD_SCHUL_CODE", ""),
            "type":          mapped_type,
            "kind_label":    kind,
            "region":        row.get("LCTN_SC_NM", ""),
            "district":      row.get("JU_ORG_NM", ""),
            "address":       (row.get("ORG_RDNMA", "") + " " + row.get("ORG_RDNDA", "")).strip(),
            "phone":         row.get("ORG_TELNO", ""),
            "homepage_url":  row.get("HMPG_ADRES", ""),
            "founder_type":  row.get("FOND_SC_NM", ""),
        })
    return results


def render_neis_school_picker(key_prefix, default_region=None, default_band="전체"):
    """⭐ NEIS 학교 검색 UI — 시·도 + 학교급 + 학교명 단계적 검색.

    어디서든 호출 가능 (학생 가입, 학부모 자녀 등록, dashboard 학교 변경 등).
    Args:
        key_prefix: streamlit widget key prefix (중복 방지)
        default_region: 기본 시·도 (예: "서울특별시" / None)
        default_band: 기본 학교급 ("전체" / "elementary" 등)
    Returns:
        dict: 선택된 학교 정보 또는 None
    """
    _regions = ["전체"] + list(NEIS_REGION_CODES.keys())
    _bands = ["전체", "elementary", "middle", "high", "special"]
    _band_labels = {"전체":"전체","elementary":"초","middle":"중","high":"고","special":"특수"}

    _c1, _c2, _c3 = st.columns([2, 2, 3])
    with _c1:
        _region = st.selectbox(
            "1️⃣ 시·도",
            _regions,
            index=(_regions.index(default_region) if default_region in _regions else 0),
            key=f"{key_prefix}_region",
        )
    with _c2:
        _band = st.selectbox(
            "2️⃣ 학교급",
            _bands,
            index=_bands.index(default_band),
            format_func=lambda x: _band_labels.get(x, x),
            key=f"{key_prefix}_band",
        )
    with _c3:
        _query = st.text_input(
            "3️⃣ 학교명 (선택 — 결과 좁히기)",
            key=f"{key_prefix}_query",
            placeholder="예: 서울대학교사범대학부설중학교",
        )

    # 검색 조건 — 시·도 또는 학교명 중 하나 이상 필요
    if _region == "전체" and not _query:
        st.caption("👉 시·도를 선택하거나 학교명을 입력하세요.")
        return None

    _region_code = NEIS_REGION_CODES.get(_region) if _region != "전체" else None
    _type_filter = None if _band == "전체" else _band

    with st.spinner("학교 검색 중..."):
        _results = neis_search_schools(
            query=_query.strip() if _query else None,
            region_code=_region_code,
            type_filter=_type_filter,
            limit=200,
        )

    if not _results:
        st.info("🔍 검색 결과가 없습니다. 다른 시·도 또는 학교명으로 시도해주세요.")
        return None

    _opts = ["(선택)"] + [
        f"{r['name']} · {r['kind_label']} · {r['region']} {r['district']}"
        for r in _results
    ]
    _picked = st.selectbox(
        f"4️⃣ 학교 선택 ({len(_results)}건)",
        _opts,
        key=f"{key_prefix}_pick",
    )
    if _picked != _opts[0]:
        _selected = _results[_opts.index(_picked) - 1]
        st.success(
            f"✅ **{_selected['name']}** ({_selected['kind_label']} · "
            f"{_selected['region']} {_selected['district']})"
        )
        return _selected
    return None


def neis_upsert_institution(school_dict):
    """NEIS 검색 결과 1건을 institutions 테이블에 upsert.

    code (NEIS 학교 코드) 기준으로 중복 체크.
    Returns: institution_id (UUID str) 또는 None
    """
    if not school_dict or not school_dict.get("code"):
        return None
    try:
        # 기존 검색 (neis_id 또는 code로)
        _q = supabase.table("institutions").select("id")\
            .or_(f"neis_id.eq.{school_dict['code']},code.eq.{school_dict['code']}")\
            .limit(1).execute()
        _existing = _q.data or []
        if _existing:
            return _existing[0].get("id")
        # 신규 INSERT
        _ins = supabase.table("institutions").insert({
            "type":         school_dict.get("type", "other"),
            "name":         school_dict.get("name", ""),
            "code":         school_dict.get("code"),
            "neis_id":      school_dict.get("neis_id"),
            "region":       school_dict.get("region"),
            "district":     school_dict.get("district"),
            "address":      school_dict.get("address"),
            "phone":        school_dict.get("phone") or None,
            "homepage_url": school_dict.get("homepage_url") or None,
            "verification_source": "neis",
            "status":       "approved",
            "approved_at":  datetime.now().isoformat(),
        }).execute()
        return (_ins.data or [{}])[0].get("id")
    except Exception:
        return None


def render_survey_respond_page():
    """⭐ Phase 7+8 Step E — 설문 응답 페이지 (token 기반 비로그인 접근)

    URL: /?survey_token=xxx 로 진입 또는 학생 본인이 dashboard에서 ✏️ 응시 클릭.
    - token으로 학생/설문 식별 (student_survey_tokens)
    - 다운로드/캡처 차단 (drag/select/contextmenu/Ctrl+S/P/U)
    - 모든 문항 응답 → '완료' 버튼 → status='completed' → 트리거가 봉사 점수 발급
    """
    _token = st.session_state.get("_survey_token") or ""
    if not _token:
        st.error("⚠️ 설문 토큰이 없습니다.")
        return

    # 토큰 조회 → 학생/설문 식별
    try:
        _tok_q = supabase.table("student_survey_tokens").select(
            "id, student_id, survey_id, response_count, revoked_at"
        ).eq("access_token", _token).limit(1).execute()
        _tok = _tok_q.data[0] if _tok_q.data else None
    except Exception:
        _tok = None

    if not _tok:
        st.error("❌ 유효하지 않은 설문 링크입니다. 다시 확인해주세요.")
        return
    if _tok.get("revoked_at"):
        st.error("❌ 이 설문 링크는 무효화되었습니다. 학생 본인에게 새 링크를 요청하세요.")
        return

    _survey_id = _tok["survey_id"]
    _student_id = _tok["student_id"]

    # 학생/설문 메타
    try:
        _stu = supabase.table("users").select("name, school_name, grade").eq("id", _student_id).single().execute().data or {}
    except Exception:
        _stu = {}
    try:
        _sv = supabase.table("surveys").select(
            "title, description, target_band, target_minutes, total_questions, min_completion_seconds"
        ).eq("id", _survey_id).single().execute().data or {}
    except Exception:
        _sv = {}

    # 다운로드/캡처 차단 CSS+JS
    st.markdown(
        """
        <style>
        .sr-page * { user-select: none !important; -webkit-user-select: none !important; -moz-user-select: none !important; }
        .sr-page img, .sr-page p, .sr-page div { -webkit-user-drag: none !important; }
        </style>
        <script>
        (function(){
            const w = window.top || window;
            try {
                w.document.addEventListener('contextmenu', function(e){ e.preventDefault(); return false; }, true);
                w.document.addEventListener('keydown', function(e){
                    const k = (e.key || '').toLowerCase();
                    // Ctrl+S / Ctrl+P / Ctrl+U / Ctrl+Shift+I (DevTools) / Ctrl+Shift+C
                    if ((e.ctrlKey || e.metaKey) && ['s','p','u'].includes(k)) { e.preventDefault(); return false; }
                    if ((e.ctrlKey || e.metaKey) && e.shiftKey && ['i','c','j'].includes(k)) { e.preventDefault(); return false; }
                    if (k === 'f12') { e.preventDefault(); return false; }
                }, true);
                w.document.addEventListener('selectstart', function(e){ e.preventDefault(); return false; }, true);
            } catch(e){}
        })();
        </script>
        """,
        unsafe_allow_html=True,
    )

    # 헤더
    st.markdown('<div class="sr-page">', unsafe_allow_html=True)
    st.markdown(f"## 📋 {_sv.get('title','캠페인 설문')}")
    if _stu.get("name"):
        st.caption(f"🎒 응답자가 캠페인을 신청한 학생: **{_stu.get('name')}** "
                   f"({_stu.get('school_name','-')} {_stu.get('grade','-') and str(_stu.get('grade'))+'학년'})")
    if _sv.get("description"):
        st.info(_sv.get("description"))

    # 이미 완료된 응답인지 확인
    try:
        _existing = supabase.table("survey_responses").select(
            "id, status, submitted_at"
        ).eq("survey_id", _survey_id).eq("student_id", _student_id).limit(1).execute()
        _resp = _existing.data[0] if _existing.data else None
    except Exception:
        _resp = None

    if _resp and _resp.get("status") == "completed":
        st.success(
            "✅ 이 설문은 이미 완료되었습니다. "
            f"({_resp.get('submitted_at','')[:10]})\n\n"
            "감사합니다. 응답이 학생의 봉사 점수에 반영되었습니다."
        )
        st.markdown('</div>', unsafe_allow_html=True)
        return

    # 문항 로드
    try:
        _qs = supabase.table("survey_questions").select(
            "id, qno, qtype, text, options, required, topic_tag"
        ).eq("survey_id", _survey_id).order("qno").execute()
        _questions = _qs.data or []
    except Exception:
        _questions = []

    if not _questions:
        st.warning("설문 문항을 불러올 수 없습니다.")
        st.markdown('</div>', unsafe_allow_html=True)
        return

    st.divider()

    # 응답 폼
    with st.form("survey_respond_form", clear_on_submit=False):
        _answers = {}
        for _q in _questions:
            _qid = _q["id"]
            _qno = _q["qno"]
            _qtype = _q["qtype"]
            _qtext = _q["text"]
            _opts = _q.get("options") or []
            _req = bool(_q.get("required"))

            _label = f"**{_qno}. {_qtext}**" + (" ⭐" if _req else " (선택)")
            st.markdown(_label)

            if _qtype == "single_choice":
                _ans = st.radio("", _opts, key=f"sr_q_{_qid}",
                                index=None, horizontal=False, label_visibility="collapsed")
                _answers[_qid] = _ans
            elif _qtype == "multi_choice":
                _ans_list = []
                for _opt in _opts:
                    if st.checkbox(_opt, key=f"sr_q_{_qid}_{_opt}"):
                        _ans_list.append(_opt)
                _answers[_qid] = _ans_list
            elif _qtype == "long_text":
                _ans = st.text_area("", key=f"sr_q_{_qid}", label_visibility="collapsed",
                                    placeholder="자유롭게 적어주세요 (선택)")
                _answers[_qid] = _ans
            elif _qtype == "short_text":
                _ans = st.text_input("", key=f"sr_q_{_qid}", label_visibility="collapsed")
                _answers[_qid] = _ans
            elif _qtype == "yes_no":
                _ans = st.radio("", ["예", "아니오"], key=f"sr_q_{_qid}",
                                index=None, horizontal=True, label_visibility="collapsed")
                _answers[_qid] = _ans
            elif _qtype == "scale":
                _ans = st.radio("", _opts, key=f"sr_q_{_qid}",
                                index=None, horizontal=True, label_visibility="collapsed")
                _answers[_qid] = _ans
            st.markdown("---")

        _submit = st.form_submit_button("✅ 모든 응답 완료 — 제출하기", type="primary",
                                        use_container_width=True)

    if _submit:
        # 필수 문항 검증
        _missing = []
        for _q in _questions:
            if not _q.get("required"):
                continue
            _v = _answers.get(_q["id"])
            if _v is None or _v == "" or (isinstance(_v, list) and not _v):
                _missing.append(_q["qno"])
        if _missing:
            st.error(f"⚠️ 필수 문항 {len(_missing)}개가 미응답입니다: " +
                     ", ".join(f"{n}번" for n in _missing[:10]) +
                     ("..." if len(_missing) > 10 else ""))
        else:
            # 응답 저장
            try:
                _now_iso = datetime.now().isoformat()
                # response upsert
                if _resp:
                    _resp_id = _resp["id"]
                    supabase.table("survey_responses").update({
                        "submitted_at": _now_iso,
                        "status": "completed",
                        "completion_rate": 100.0,
                        "integrity_score": 85,  # 기본 통과 점수 (성실도 자동 산정은 추후)
                        "access_token": _token,
                        "access_source": "link",
                    }).eq("id", _resp_id).execute()
                else:
                    _ins = supabase.table("survey_responses").insert({
                        "survey_id": _survey_id,
                        "student_id": _student_id,
                        "started_at": _now_iso,
                        "submitted_at": _now_iso,
                        "status": "in_progress",  # answers 저장 후 completed로 update (트리거 발화)
                        "completion_rate": 100.0,
                        "integrity_score": 85,
                        "access_token": _token,
                        "access_source": "link",
                    }).execute()
                    _resp_id = (_ins.data or [{}])[0].get("id")

                # answers bulk insert
                _ans_rows = []
                for _q in _questions:
                    _v = _answers.get(_q["id"])
                    if _v is None or _v == "" or (isinstance(_v, list) and not _v):
                        continue
                    import json as _json
                    _ans_rows.append({
                        "response_id": _resp_id,
                        "question_id": _q["id"],
                        "answer": _v,  # supabase-py가 dict/list/str 자동 JSON 변환
                    })
                if _ans_rows:
                    # 기존 답변 제거 후 신규 입력
                    supabase.table("survey_answers").delete().eq("response_id", _resp_id).execute()
                    supabase.table("survey_answers").insert(_ans_rows).execute()

                # 완료 → 트리거가 봉사 발급
                supabase.table("survey_responses").update({
                    "status": "completed",
                }).eq("id", _resp_id).execute()

                st.balloons()
                st.success(
                    "🎉 설문 응답이 완료되었습니다!\n\n"
                    f"학생 **{_stu.get('name','')}** 의 봉사 점수에 반영됩니다. "
                    "참여해주셔서 감사합니다."
                )
                # token 정리
                st.session_state.pop("_survey_token", None)
            except Exception as _e:
                st.error(f"응답 저장 실패: {_e}")
    st.markdown('</div>', unsafe_allow_html=True)


# ══════════════════════════════
# 📱 휴대폰 본인인증 (캠페인 가입 공통) — NICE/PASS 공식 연동 자리 + 임시 폴백
# ══════════════════════════════
def _idv_nice_configured():
    """공식 NICE 본인인증 키가 환경변수(Railway)에 설정되어 있는지."""
    return bool(os.environ.get("NICE_CLIENT_ID") and os.environ.get("NICE_CLIENT_SECRET"))


def _render_identity_verification(role_key):
    """휴대폰 본인인증 게이트 — st.form 밖에서 호출. 결과를 session_state['_idv_<role>']에 저장.
    반환: dict(verified/name/phone/birth/age/is_minor) 또는 None.
    공식 NICE 키가 설정되면 NICE 흐름, 아니면 임시(휴대폰번호+생년월일→미성년 판별) 폴백.
    """
    _k = f"_idv_{role_key}"
    _res = st.session_state.get(_k)
    st.markdown("##### 📱 휴대폰 본인인증 (필수)")
    if _res and _res.get("verified"):
        _age = _res.get("age")
        _agetxt = f"만 {_age}세" if _age is not None else "나이 미상"
        st.success(
            f"✅ 본인인증 완료 — {_res.get('name','')} / {_agetxt}"
            + ("  ⚠️ 미성년자" if _res.get("is_minor") else "")
        )
        if st.button("🔄 다시 인증", key=f"idv_reset_{role_key}"):
            st.session_state.pop(_k, None)
            st.rerun()
        return _res

    st.caption("미성년자 여부 확인을 위해 본인 명의 휴대폰으로 인증합니다.")
    if _idv_nice_configured():
        st.info("📱 NICE 공식 휴대폰 본인인증으로 진행합니다.")
        if st.button("📱 NICE 휴대폰 본인인증 시작", key=f"idv_nice_{role_key}",
                     type="primary", use_container_width=True):
            # TODO(키 수령 후): NICE 표준창 토큰 발급 → window.open → 콜백(enc_data) 복호화 → 결과 저장
            st.warning("NICE 연동 키는 설정되었으나 콜백 검증이 필요합니다. 관리자에게 문의해주세요.")
        return None

    # 임시 폴백 — 공식 키 설정 전. 휴대폰번호+이름+생년월일로 미성년 여부 판별.
    st.info("⚠️ 공식 본인인증(NICE/PASS) 연동 키 설정 전 **임시 인증**입니다. (정식 연동 시 자동 전환)")
    _nm = st.text_input("이름 *", key=f"idv_nm_{role_key}")
    _ph = st.text_input("휴대폰번호 *", placeholder="010-0000-0000", key=f"idv_ph_{role_key}")
    _bd = st.date_input("생년월일 *", value=None, min_value=date(1930, 1, 1),
                        max_value=date.today(), key=f"idv_bd_{role_key}")
    if st.button("✅ 휴대폰 본인인증 (임시)", key=f"idv_tmp_{role_key}",
                 type="primary", use_container_width=True):
        import re as _re
        if not (_nm and _ph and _bd):
            st.warning("이름·휴대폰번호·생년월일을 모두 입력해주세요.")
        elif not _re.match(r"^01[016789]-?\d{3,4}-?\d{4}$", _ph.replace(" ", "")):
            st.warning("올바른 휴대폰번호 형식이 아닙니다. 예: 010-1234-5678")
        else:
            _age = _campaign_calc_age(_bd)
            st.session_state[_k] = {
                "verified": True, "name": _nm, "phone": _ph, "birth": str(_bd),
                "age": _age, "is_minor": (_age is not None and _age < 19),
                "method": "temp",
            }
            st.rerun()
    return st.session_state.get(_k)


def render_campaign_signup_page(page_key):
    """캠페인 회원가입 페이지 렌더링.
    page_key: 'campaign_signup_select' | 'campaign_signup_institution'
            | 'campaign_signup_parent' | 'campaign_signup_student'
    """
    # 🔁 새로고침해도 현재 가입 단계 유지 — URL에 signup 파라미터 동기화
    try:
        st.query_params["signup"] = page_key.replace("campaign_signup_", "")
    except Exception:
        pass

    # 상단 헤더 + 전단계로 가기
    _h1, _h2 = st.columns([5, 2])
    with _h1:
        st.markdown("## 🎓 캠페인 회원가입")
    with _h2:
        if st.button("← 전단계로 가기", key=f"signup_back_{page_key}", use_container_width=True):
            st.session_state["login_mode"] = "campaign"
            st.session_state["current_page"] = None
            try:
                if "signup" in st.query_params:
                    del st.query_params["signup"]
            except Exception:
                pass
            st.rerun()
    st.divider()

    if page_key == "campaign_signup_select":
        _render_signup_select()
    elif page_key == "campaign_signup_institution":
        _render_signup_institution()
    elif page_key == "campaign_signup_parent":
        _render_signup_parent()
    elif page_key == "campaign_signup_student":
        _render_signup_student()
    else:
        st.error("알 수 없는 회원가입 페이지입니다.")


def _render_signup_select():
    """3카드 — 교육기관 / 학부모 / 학생 선택."""
    st.markdown("### 어떤 자격으로 가입하시나요?")
    st.caption("선택에 따라 가입 폼과 권한이 달라집니다.")
    st.markdown("")

    _c1, _c2, _c3 = st.columns(3, gap="large")
    with _c1:
        with st.container(border=True):
            st.markdown("##### 🏫 교육기관")
            st.markdown(
                "- 교육부 / 시도교육청 / 초·중·고\n"
                "- 교육부 인가 청소년 교육시설\n"
                "- 소속 학생 일괄 관리\n"
                "- 봉사 점수 일괄 발급\n"
                "- 연단위 / 일괄 계약"
            )
            if st.button("🏫 교육기관으로 가입", type="primary", use_container_width=True, key="signup_card_inst"):
                st.session_state["current_page"] = "campaign_signup_institution"
                st.rerun()
    with _c2:
        with st.container(border=True):
            st.markdown("##### 👨‍👩‍👧 학부모")
            st.markdown(
                "- 자녀 등록 (다자녀 가능)\n"
                "- 연 1만 7천원 — 모든 유료 자료\n"
                "- 자녀 설문 모니터링\n"
                "- 모니터링 시스템도 동일 ID로 이용\n"
                "- 만 14세 미만 자녀 동의 처리"
            )
            if st.button("👨‍👩‍👧 학부모로 가입", type="primary", use_container_width=True, key="signup_card_parent"):
                st.session_state["current_page"] = "campaign_signup_parent"
                st.rerun()
    with _c3:
        with st.container(border=True):
            st.markdown("##### 🎒 학생")
            st.markdown(
                "- 무료 자료 학습\n"
                "- 50문항 설문 → 봉사 4~8시간\n"
                "- 활동 내역 출력 / 이메일\n"
                "- ⚠️ 모니터링 시스템 접근 불가\n"
                "- 만 14세 미만 학부모 동의 필요"
            )
            if st.button("🎒 학생으로 가입", type="primary", use_container_width=True, key="signup_card_stu"):
                st.session_state["current_page"] = "campaign_signup_student"
                st.rerun()


def _render_signup_institution():
    """교육기관 회원가입 — 기존 기관 선택 또는 신규 등록 신청."""
    st.markdown("### 🏫 교육기관 가입")
    st.caption("등록된 기관의 관리자로 가입하거나, 신규 기관 등록을 신청할 수 있습니다.")

    # 기존 기관 목록 (approved만)
    try:
        _insts = supabase.table("institutions").select(
            "id, type, name, region, district"
        ).eq("status", "approved").is_("deleted_at", "null").order("name").limit(2000).execute().data or []
    except Exception:
        _insts = []

    _mode = st.radio(
        "가입 방식",
        ["📋 등록된 기관에서 선택", "🏫 NEIS에서 학교 검색", "🆕 신규 기관 등록 신청"],
        horizontal=True, key="inst_signup_mode",
    )
    _is_new_inst = (_mode == "🆕 신규 기관 등록 신청")
    _is_neis_mode = (_mode == "🏫 NEIS에서 학교 검색")

    # ⭐ NEIS 검색 (폼 밖)
    _neis_selected_school = None
    if _is_neis_mode:
        st.markdown("##### 🔍 NEIS 학교 검색")
        _nq1, _nq2 = st.columns([3, 1])
        with _nq1:
            _neis_q = st.text_input("학교명 검색 (2자 이상)",
                                     key="inst_signup_neis_q",
                                     placeholder="예: 서울중앙초등학교")
        with _nq2:
            _neis_tf = st.selectbox("학교급",
                                     ["전체", "elementary", "middle", "high", "special"],
                                     format_func=lambda x: {"전체":"전체","elementary":"초","middle":"중","high":"고","special":"특수"}.get(x, x),
                                     key="inst_signup_neis_tf")
        if _neis_q and len(_neis_q.strip()) >= 2:
            _tf = None if _neis_tf == "전체" else _neis_tf
            _ns_res = neis_search_schools(_neis_q, type_filter=_tf, limit=30)
            if _ns_res:
                _opts_n = ["(선택 안 함)"] + [
                    f"{r['name']} · {r['kind_label']} · {r['region']} · {r['founder_type']}"
                    for r in _ns_res
                ]
                _pck = st.selectbox(f"검색 결과 ({len(_ns_res)}건)", _opts_n,
                                     key="inst_signup_neis_pick")
                if _pck != _opts_n[0]:
                    _idx = _opts_n.index(_pck) - 1
                    _neis_selected_school = _ns_res[_idx]
                    st.success(f"✅ 선택: **{_neis_selected_school['name']}** "
                              f"({_neis_selected_school['kind_label']} · {_neis_selected_school['region']})")
                    st.caption(f"주소: {_neis_selected_school['address']} · 전화: {_neis_selected_school['phone']}")
            else:
                st.info("🔍 NEIS 검색 결과 없음.")

    _render_identity_verification("institution")
    with st.form("inst_signup_form"):
        st.markdown("##### 👤 가입자 정보 (기관 담당자)")
        c1, c2 = st.columns(2)
        with c1:
            _name = st.text_input("이름 *", placeholder="홍길동")
            _email = st.text_input("이메일 *", placeholder="staff@school.kr")
        with c2:
            _phone = st.text_input("연락처", placeholder="010-0000-0000")
            _title = st.text_input("직책", placeholder="예: 학생부장")

        c3, c4 = st.columns(2)
        with c3:
            _pw1 = st.text_input("비밀번호 * (6자 이상)", type="password")
        with c4:
            _pw2 = st.text_input("비밀번호 확인 *", type="password")

        st.divider()
        st.markdown("##### 🏫 기관 정보")

        _inst_id_selected = None
        _new_inst_data = {}
        if _is_neis_mode and _neis_selected_school:
            st.info(f"🏫 NEIS 선택 학교: **{_neis_selected_school['name']}** "
                   f"({_neis_selected_school['kind_label']} · {_neis_selected_school['region']})")
            st.caption("가입 신청 시 NEIS 정보로 institutions에 자동 등록됩니다.")
        elif _is_new_inst:
            ic1, ic2 = st.columns(2)
            with ic1:
                _new_inst_data["type"] = st.selectbox(
                    "기관 유형 *",
                    ["elementary", "middle", "high", "special",
                     "metro_office", "district_office",
                     "metro_council", "local_council",
                     "ministry", "youth_facility", "other"],
                    format_func=lambda x: {
                        "elementary":"초등학교", "middle":"중학교", "high":"고등학교",
                        "special":"특수학교",
                        "metro_office":"시·도 교육청", "district_office":"교육지원청",
                        "metro_council":"시·도의회 교육위원회",
                        "local_council":"시·군·구의회 교육위원회",
                        "ministry":"교육부",
                        "youth_facility":"교육부 인가 청소년 시설",
                        "other":"기타 (수기 등록)",
                    }.get(x, x),
                    help="학교는 NEIS 검색 권장 · 교육청/교육위원회/예외는 수기 등록",
                )
                _new_inst_data["name"] = st.text_input("기관명 *", placeholder="(예) 서울중앙초등학교")
                _new_inst_data["region"] = st.text_input("시도", placeholder="서울특별시")
                _new_inst_data["district"] = st.text_input("시군구", placeholder="강남구")
            with ic2:
                _new_inst_data["address"] = st.text_input("주소", placeholder="(상세 주소)")
                _new_inst_data["phone"] = st.text_input("대표 전화")
                _new_inst_data["representative"] = st.text_input("교장/대표자")
                _new_inst_data["code"] = st.text_input("기관 코드 (선택)", placeholder="NEIS 학교 코드 등")

            # ⭐ 사업자등록증 업로드 (필수)
            st.markdown("##### 📎 사업자등록증 첨부 (필수)")
            st.caption(
                "교육기관의 사업자등록증 사본 또는 학교 인가증을 PDF·JPG·PNG로 업로드해주세요. "
                "본부 검증 후 승인 처리됩니다."
            )
            _biz_lic = st.file_uploader(
                "사업자등록증 / 학교 인가증 파일 *",
                type=["pdf","jpg","jpeg","png"],
                key="inst_signup_biz_lic",
                help="최대 5MB. 본부 admin만 열람 가능 (보안 보장).",
            )
            if _biz_lic:
                st.success(f"✅ 파일 업로드 준비됨: {_biz_lic.name} ({_biz_lic.size/1024:.1f} KB)")
                _new_inst_data["_biz_lic_filename"] = _biz_lic.name
                _new_inst_data["_biz_lic_size"] = _biz_lic.size
            st.info("📌 신규 기관 등록은 본부 관리자가 사업자등록증을 확인한 후 승인됩니다. (검토 1~3일 소요)")
        else:
            if not _insts:
                st.warning("등록된 기관이 없습니다. '신규 기관 등록 신청'을 선택해주세요.")
                _inst_id_selected = None
            else:
                _opts = {f'{i["name"]} ({i.get("region","")} {i.get("district","")})': i["id"]
                         for i in _insts}
                _sel_label = st.selectbox("소속 기관 선택 *", list(_opts.keys()))
                _inst_id_selected = _opts.get(_sel_label)

        st.markdown("")
        _agree = st.checkbox("개인정보 수집·이용 및 서비스 이용약관에 동의합니다.", value=False)

        _submitted = st.form_submit_button("✅ 가입 신청", type="primary", use_container_width=True)

    if _submitted:
        _idv = st.session_state.get("_idv_institution")
        if not (_idv and _idv.get("verified")):
            st.error("📱 휴대폰 본인인증을 먼저 완료해주세요.")
            return
        if not _agree:
            st.error("약관에 동의해주세요.")
            return
        if not _name or not _email or not _pw1:
            st.error("필수 항목(이름·이메일·비밀번호)을 입력해주세요.")
            return
        if _pw1 != _pw2:
            st.error("비밀번호가 일치하지 않습니다.")
            return
        if len(_pw1) < 6:
            st.error("비밀번호는 6자 이상이어야 합니다.")
            return
        if _is_new_inst and not _new_inst_data.get("name"):
            st.error("기관명을 입력해주세요.")
            return
        if _is_new_inst and not _new_inst_data.get("_biz_lic_filename"):
            st.error("📎 **사업자등록증/학교 인가증**을 업로드해주세요. (신규 등록 시 필수)")
            return
        if _is_neis_mode and not _neis_selected_school:
            st.error("NEIS에서 학교를 검색·선택해주세요.")
            return
        if (not _is_new_inst) and (not _is_neis_mode) and (not _inst_id_selected):
            st.error("소속 기관을 선택해주세요.")
            return

        # 1. Auth 생성
        with st.spinner("가입 처리 중..."):
            _uid, _err = _campaign_create_auth_user(_email, _pw1, _name)
            if _err:
                st.error(f"❌ {_err}")
                return

            # 2. NEIS 모드면 institutions에 즉시 upsert (승인 대기 X — 자동 승인)
            _final_inst_id = _inst_id_selected
            if _is_neis_mode and _neis_selected_school:
                _upsert_id = neis_upsert_institution(_neis_selected_school)
                if _upsert_id:
                    _final_inst_id = _upsert_id

            # 2b. 신규 기관이면 institution_requests에 add 신청 + 사업자등록증 업로드
            if _is_new_inst:
                # 사업자등록증 Supabase Storage 업로드
                _biz_lic_url = None
                _biz_lic_path = None
                try:
                    if _biz_lic:
                        _ext = _biz_lic.name.rsplit(".", 1)[-1].lower() if "." in _biz_lic.name else "bin"
                        _biz_lic_path = f"business_licenses/{_uid}_{int(datetime.now().timestamp())}.{_ext}"
                        _biz_lic.seek(0)
                        sb_admin().storage.from_("Documents").upload(
                            _biz_lic_path,
                            _biz_lic.read(),
                            {"content-type": _biz_lic.type or "application/octet-stream"},
                        )
                        # signed URL (1년 유효 — 본부 admin이 검토용)
                        _biz_lic_url = sb_admin().storage.from_("Documents")\
                            .create_signed_url(_biz_lic_path, 60 * 60 * 24 * 365)["signedURL"]
                except Exception as _se:
                    st.warning(f"사업자등록증 업로드 실패 (가입은 진행됨): {_se}")
                # _new_inst_data에 license 정보 추가
                _new_inst_data.pop("_biz_lic_filename", None)
                _new_inst_data.pop("_biz_lic_size", None)
                _new_inst_data["business_license_path"] = _biz_lic_path
                _new_inst_data["business_license_url"] = _biz_lic_url
                try:
                    _req = supabase.table("institution_requests").insert({
                        "request_type": "add",
                        "requested_by": _uid,
                        "requested_data": _new_inst_data,
                        "note": f"가입 시 신규 등록 신청 — 담당자 {_name}. 사업자등록증 첨부: "
                                f"{'있음' if _biz_lic_url else '없음'}",
                    }).execute()
                    _final_inst_id = None  # 승인 전까지 미연결
                except Exception as e:
                    st.warning(f"기관 신청 저장 실패(가입은 진행): {e}")

            # 3. public.users INSERT
            try:
                supabase.table("users").insert({
                    "id": _uid,
                    "email": _email,
                    "name": _name,
                    "phone": _phone or None,
                    "role": "user",
                    "role_v2": "institution_admin",
                    "is_campaign_only": False,  # 기관 사용자는 모니터링 연동 가능
                    "institution_id": _final_inst_id,
                    "status": "active",
                    "preferences": {"campaign_title": _title or ""},
                }).execute()
            except Exception as e:
                st.error(f"❌ 사용자 정보 저장 실패: {e}")
                return

        st.success("🎉 가입 신청 완료! 로그인 페이지에서 로그인해주세요.")
        st.balloons()
        st.session_state["current_page"] = None
        try:
            if "signup" in st.query_params:
                del st.query_params["signup"]
        except Exception:
            pass
        if st.button("🚪 로그인 페이지로 이동", type="primary"):
            st.rerun()


def _render_signup_parent():
    """학부모 회원가입."""
    st.markdown("### 👨‍👩‍👧 학부모 가입")
    st.caption("가입 후 자녀를 등록하실 수 있습니다. 자녀는 가입 후 대시보드에서 추가 가능.")

    _render_identity_verification("parent")
    with st.form("parent_signup_form"):
        st.markdown("##### 👤 학부모 정보")
        c1, c2 = st.columns(2)
        with c1:
            _name = st.text_input("이름 *", placeholder="홍길동")
            _email = st.text_input("이메일 *", placeholder="parent@example.com")
        with c2:
            _phone = st.text_input("연락처 *", placeholder="010-0000-0000")
            _relationship = st.selectbox(
                "관계", ["mother", "father", "guardian", "grandparent", "other"],
                format_func=lambda x: {"mother":"모", "father":"부", "guardian":"후견인",
                                       "grandparent":"조부모", "other":"기타"}.get(x, x),
            )

        c3, c4 = st.columns(2)
        with c3:
            _pw1 = st.text_input("비밀번호 * (6자 이상)", type="password")
        with c4:
            _pw2 = st.text_input("비밀번호 확인 *", type="password")

        st.divider()
        st.caption("📌 학부모 회원은 모니터링 시스템도 동일 ID로 이용 가능합니다.")
        st.caption("📌 연 1만 7천원 결제 시 등록된 모든 자녀가 유료 자료를 무제한 열람할 수 있습니다.")
        st.markdown("")

        _agree = st.checkbox("개인정보 수집·이용 및 서비스 이용약관에 동의합니다.", value=False)
        _consent = st.checkbox("만 14세 미만 자녀를 등록할 경우 보호자 권한으로 동의함을 확인합니다.", value=False)

        _submitted = st.form_submit_button("✅ 학부모 가입", type="primary", use_container_width=True)

    if _submitted:
        _idv = st.session_state.get("_idv_parent")
        if not (_idv and _idv.get("verified")):
            st.error("📱 휴대폰 본인인증을 먼저 완료해주세요.")
            return
        if not (_agree and _consent):
            st.error("약관과 보호자 동의 항목 모두 체크해주세요.")
            return
        if not _name or not _email or not _pw1 or not _phone:
            st.error("필수 항목을 입력해주세요.")
            return
        if _pw1 != _pw2:
            st.error("비밀번호가 일치하지 않습니다.")
            return
        if len(_pw1) < 6:
            st.error("비밀번호는 6자 이상이어야 합니다.")
            return

        with st.spinner("가입 처리 중..."):
            _uid, _err = _campaign_create_auth_user(_email, _pw1, _name)
            if _err:
                st.error(f"❌ {_err}")
                return
            try:
                supabase.table("users").insert({
                    "id": _uid,
                    "email": _email,
                    "name": _name,
                    "phone": _phone or None,
                    "notify_phone": _phone or None,
                    "role": "user",
                    "role_v2": "parent",
                    "is_campaign_only": False,
                    "status": "active",
                    "preferences": {"parent_relationship_default": _relationship},
                }).execute()
            except Exception as e:
                st.error(f"❌ 저장 실패: {e}")
                return

        st.success("🎉 학부모 가입 완료! 로그인 후 자녀를 등록해주세요.")
        st.balloons()
        st.session_state["current_page"] = None
        try:
            if "signup" in st.query_params:
                del st.query_params["signup"]
        except Exception:
            pass
        if st.button("🚪 로그인 페이지로 이동", type="primary"):
            st.rerun()


def _render_signup_student():
    """학생 회원가입 — 3경로 (자가/학교일괄/학부모생성)."""
    st.markdown("### 🎒 학생 가입")
    st.warning(
        "⚠️ **학생은 캠페인 시스템만 이용 가능합니다.** "
        "유해 컨텐츠 모니터링 시스템에는 접근할 수 없습니다."
    )

    _path = st.radio(
        "가입 경로",
        ["✏️ 직접 가입 (자가)", "🏫 학교에서 받은 일괄 가입 코드", "👨‍👩‍👧 학부모가 등록"],
        horizontal=True, key="stu_signup_path",
    )
    _signup_source = {
        "✏️ 직접 가입 (자가)": "self",
        "🏫 학교에서 받은 일괄 가입 코드": "institution_bulk",
        "👨‍👩‍👧 학부모가 등록": "parent_create",
    }[_path]

    if _signup_source == "parent_create":
        st.info("학부모가 자녀를 등록하시려면 먼저 **학부모 회원가입** 후 로그인하여 대시보드에서 자녀를 추가해주세요.")
        if st.button("👨‍👩‍👧 학부모 가입으로 이동", use_container_width=True):
            st.session_state["current_page"] = "campaign_signup_parent"
            st.rerun()
        return

    # ⭐ NEIS 학교 검색 (헬퍼 — 시·도 → 학교급 → 학교명 단계적 검색)
    st.markdown("##### 🏫 재학 중인 학교 검색 (NEIS Open API)")
    _selected_school = render_neis_school_picker("signup_student_school")
    _selected_inst_id = None

    # 기존 institutions 표 (NEIS 미사용 시 fallback)
    try:
        _insts = supabase.table("institutions").select("id, name, region, district").eq(
            "status", "approved").is_("deleted_at", "null").in_(
            "type", ["elementary", "middle", "high", "special"]).order("name").limit(2000).execute().data or []
    except Exception:
        _insts = []

    _render_identity_verification("student")
    with st.form("student_signup_form"):
        st.markdown("##### 👤 학생 정보")
        c1, c2 = st.columns(2)
        with c1:
            _name = st.text_input("이름 *")
            _email = st.text_input("이메일 *", placeholder="student@example.com",
                                   help="학생 본인 이메일. 없으면 학부모 동의 후 학부모 이메일도 가능.")
            _birth = st.date_input("생년월일 *", value=None, min_value=date(2005, 1, 1), max_value=date.today())
        with c2:
            _grade = st.number_input("학년", min_value=1, max_value=12, value=6, step=1)
            if _selected_school:
                st.text_input("선택한 학교 (NEIS)", value=_selected_school["name"], disabled=True)
                _inst_id = None  # 폼 제출 시 _selected_school로 upsert
                _school_name = _selected_school["name"]
            elif _insts:
                _opts = {f'{i["name"]} ({i.get("region","")} {i.get("district","")})': i["id"] for i in _insts}
                _opts = {"(직접 입력)": None, **_opts}
                _sel = st.selectbox("재학 중 학교 (기존 등록)", list(_opts.keys()))
                _inst_id = _opts.get(_sel)
                _school_name = st.text_input("학교명 (위에서 안 나오면 직접 입력)", value="")
            else:
                _inst_id = None
                _school_name = st.text_input("학교명 (직접 입력)", value="")

        c3, c4 = st.columns(2)
        with c3:
            _pw1 = st.text_input("비밀번호 * (6자 이상)", type="password")
        with c4:
            _pw2 = st.text_input("비밀번호 확인 *", type="password")

        # 학교 일괄 코드
        _bulk_code = None
        if _signup_source == "institution_bulk":
            _bulk_code = st.text_input("학교 일괄 가입 코드 *",
                                       placeholder="학교에서 받은 코드 입력",
                                       help="학교가 발급한 일괄 등록 코드 — 추후 활성화")

        # 학부모 정보 (자가 가입 시 옵션)
        st.divider()
        st.markdown("##### 👨‍👩‍👧 보호자 정보 (만 14세 미만은 필수)")
        pc1, pc2 = st.columns(2)
        with pc1:
            _parent_name = st.text_input("보호자 이름")
            _parent_email = st.text_input("보호자 이메일", placeholder="보호자에게 동의 요청 메일 발송")
        with pc2:
            _parent_phone = st.text_input("보호자 연락처")

        st.markdown("")
        _agree = st.checkbox("개인정보 수집·이용 및 서비스 이용약관에 동의합니다.", value=False)

        _submitted = st.form_submit_button("✅ 학생 가입", type="primary", use_container_width=True)

    if _submitted:
        _idv = st.session_state.get("_idv_student")
        if not (_idv and _idv.get("verified")):
            st.error("📱 휴대폰 본인인증을 먼저 완료해주세요.")
            return
        if not _agree:
            st.error("약관에 동의해주세요.")
            return
        if not _name or not _email or not _pw1 or not _birth:
            st.error("필수 항목(이름·이메일·비밀번호·생년월일)을 입력해주세요.")
            return
        if _pw1 != _pw2:
            st.error("비밀번호가 일치하지 않습니다.")
            return
        if len(_pw1) < 6:
            st.error("비밀번호는 6자 이상이어야 합니다.")
            return

        # 만 14세 미만 → 보호자 정보 필수
        _age = _campaign_calc_age(_birth)
        if _age is not None and _age < 14:
            if not (_parent_name and _parent_email):
                st.error(f"⚠️ 만 {_age}세 학생은 보호자 정보(이름·이메일)가 필수입니다. (개인정보보호법)")
                return

        if _signup_source == "institution_bulk" and not _bulk_code:
            st.error("학교 일괄 가입 코드를 입력해주세요.")
            return

        # ⭐ NEIS 선택 학교가 있으면 institutions에 upsert → institution_id 확보
        if _selected_school:
            _upserted_id = neis_upsert_institution(_selected_school)
            if _upserted_id:
                _inst_id = _upserted_id
                _school_name = _selected_school["name"]

        with st.spinner("가입 처리 중..."):
            _uid, _err = _campaign_create_auth_user(_email, _pw1, _name)
            if _err:
                st.error(f"❌ {_err}")
                return
            try:
                _payload = {
                    "id": _uid,
                    "email": _email,
                    "name": _name,
                    "role": "user",
                    "role_v2": "student",
                    "is_campaign_only": True,  # 학생은 캠페인 전용 — 모니터링 차단
                    "signup_source": _signup_source,
                    "birth_date": _birth.isoformat() if _birth else None,
                    "grade": int(_grade) if _grade else None,
                    "institution_id": _inst_id,
                    "school_name": _school_name or None,
                    "status": "active",
                    "guardian_name": _parent_name or None,
                    "guardian_phone": _parent_phone or None,
                    "preferences": {
                        "guardian_email": _parent_email or "",
                        "bulk_code_used": _bulk_code or "",
                    },
                }
                # 만 14세 이상이거나 보호자 정보가 있어 동의 처리된 경우
                if _age is None or _age >= 14:
                    _payload["parent_consent_at"] = datetime.now().isoformat()
                # 만 14세 미만 + 보호자 정보 입력 → pending (실제 학부모 동의 메일은 Phase 4)
                supabase.table("users").insert(_payload).execute()
            except Exception as e:
                st.error(f"❌ 저장 실패: {e}")
                return

        if _age is not None and _age < 14:
            st.success("🎉 학생 가입 신청 완료! 보호자 동의 확인 후 활성화됩니다.")
        else:
            st.success("🎉 학생 가입 완료! 로그인 후 캠페인을 시작해주세요.")
        st.balloons()
        st.session_state["current_page"] = None
        try:
            if "signup" in st.query_params:
                del st.query_params["signup"]
        except Exception:
            pass
        if st.button("🚪 로그인 페이지로 이동", type="primary"):
            st.rerun()


# ══════════════════════════════════════════════════════════════════
# (기존) login 함수
# ══════════════════════════════════════════════════════════════════

def _send_admin_otp(email, otp):
    """관리자 MFA 인증코드 이메일 발송 (Resend). 성공 시 True, 실패 시 False(→잠금방지 폴백)."""
    try:
        if not RESEND_AVAILABLE:
            return False
        _key = os.getenv("RESEND_API_KEY")
        if not _key:
            return False
        resend.api_key = _key
        resend.Emails.send({
            "from": "AI agent_dragoneyes <dragoneyes@dragoneyes.co.kr>",
            "to": [email],
            "subject": "[드래곤아이즈] 관리자 로그인 인증코드",
            "html": (
                "<div style='font-family:Arial,sans-serif;max-width:480px;margin:0 auto;padding:20px;'>"
                "<h2 style='color:#0f3460;'>🐉 관리자 로그인 인증</h2>"
                "<p>아래 6자리 인증코드를 입력하세요. (5분간 유효)</p>"
                f"<p style='font-size:30px;font-weight:bold;letter-spacing:6px;color:#1d4ed8;'>{otp}</p>"
                "<p style='color:#64748b;font-size:13px;'>본인이 요청하지 않았다면 이 메일을 무시하세요.</p>"
                "</div>"
            ),
        })
        return True
    except Exception as e:
        print(f"[MFA OTP] send failed: {e}")
        return False

def _finalize_login(_u, access_token, refresh_token, email):
    """로그인 최종 확정 — session_state·세션ID·라우팅. (일반/관리자 MFA 통과 후 공용)"""
    st.session_state.user = _u
    st.session_state.access_token = access_token
    st.session_state.refresh_token = refresh_token
    st.session_state.report_count = get_month_count(_u["id"])
    accessibility.load_from_user(_u)
    _set_session_param(refresh_token, email)
    _is_partner_admin = (
        _u.get("partner_role") == "partner_admin"
        or _u.get("is_tenant_admin")
        or (_u.get("role") == "admin" and _u.get("partner_id"))
    )
    st.session_state.current_page = "agency_dashboard" if _is_partner_admin else "home_landing"

def login(email, password):
    try:
        result = supabase.auth.sign_in_with_password({"email": email, "password": password})
        if result.user:
            ud = supabase.table("users").select("*").eq("email", email).execute()
            if ud.data:
                _u = ud.data[0]
                # ─── 🚫 주말 차단 검사 (일반 사용자만) ───
                from datetime import datetime as _dt_login
                _role = _u.get("role_v2", "user")
                _is_weekend = _dt_login.now().weekday() >= 5  # 5=토, 6=일
                # 본부/파트너/총판 admin은 주말에도 접속 가능
                _is_admin_role = (
                    _u.get("role") == "admin"
                    or _u.get("partner_role") == "partner_admin"
                    or _u.get("hq_position")
                    or _u.get("distributor_id")
                    or _u.get("is_tenant_admin")
                )
                if _role == "user" and _is_weekend and not _is_admin_role:
                    return False, "📅 주말 보안 정책에 따라 일반 사용자는 토요일/일요일에 접속할 수 없습니다. 평일에 다시 시도해주세요."

                # ─── 🔐 관리자 MFA (이메일 OTP) — 관리자 계정만, 일반 사용자는 불편 없게 제외 ───
                _needs_mfa = (
                    _u.get("role") in ("admin", "superadmin")
                    or _u.get("partner_role") == "partner_admin"
                    or _u.get("is_tenant_admin")
                    or _u.get("hq_position")
                )
                if _needs_mfa:
                    _otp = f"{_secrets.randbelow(900000) + 100000}"
                    if _send_admin_otp(email, _otp):
                        st.session_state["_mfa_pending"] = {
                            "user": _u,
                            "access_token": result.session.access_token,
                            "refresh_token": result.session.refresh_token,
                            "email": email, "otp": _otp,
                            "expires": (datetime.now() + timedelta(minutes=5)).isoformat(),
                            "attempts": 0,
                        }
                        return None, "MFA_SENT"
                    # 이메일 발송 실패 → 잠금 방지: MFA 건너뛰고 정상 로그인 (운영자 락아웃 방지)
                # ─── 정상 로그인 ───
                _finalize_login(_u, result.session.access_token, result.session.refresh_token, email)
                return True, "로그인 성공"
            return False, "사용자 정보를 찾을 수 없습니다."
    except Exception as e:
        return False, f"로그인 실패: {str(e)}"
    return False, "로그인 실패"

def is_weekday():
    return True

def get_chat_token_info(user_id):
    ym = date.today().strftime("%Y-%m")
    res = supabase.table("chat_tokens").select("*").eq("user_id", user_id).eq("year_month", ym).execute()
    if res.data:
        return res.data[0]
    supabase.table("chat_tokens").insert({
        "user_id": user_id, "year_month": ym,
        "used_count": 0, "extra_tokens": 0
    }).execute()
    return {"used_count": 0, "extra_tokens": 0}

def get_chat_today_count(user_id):
    today = date.today().isoformat()
    res = supabase.table("chat_logs").select("id").eq("user_id", user_id).gte("created_at", today).execute()
    return len(res.data)

def get_chat_week_count(user_id):
    today = date.today()
    monday = today - timedelta(days=today.weekday())
    res = supabase.table("chat_logs").select("id").eq("user_id", user_id).gte("created_at", monday.isoformat()).execute()
    return len(res.data)

def can_use_chat(user_id):
    if not is_weekday():
        return {"ok": False, "reason": "weekend"}
    info = get_chat_token_info(user_id)
    monthly_limit = CHAT_MONTHLY_LIMIT + info.get("extra_tokens", 0)
    monthly_used = info["used_count"]
    today_used = get_chat_today_count(user_id)
    week_used = get_chat_week_count(user_id)
    if monthly_used >= monthly_limit:
        return {"ok": False, "reason": "monthly", "monthly_used": monthly_used, "monthly_limit": monthly_limit, "today_used": today_used, "week_used": week_used}
    if week_used >= CHAT_WEEKLY_LIMIT:
        return {"ok": False, "reason": "weekly", "monthly_used": monthly_used, "monthly_limit": monthly_limit, "today_used": today_used, "week_used": week_used}
    if today_used >= CHAT_DAILY_LIMIT:
        return {"ok": False, "reason": "daily", "monthly_used": monthly_used, "monthly_limit": monthly_limit, "today_used": today_used, "week_used": week_used}
    return {
        "ok": True, "reason": None,
        "monthly_used": monthly_used, "monthly_limit": monthly_limit,
        "monthly_remaining": monthly_limit - monthly_used,
        "today_used": today_used, "today_remaining": CHAT_DAILY_LIMIT - today_used,
        "week_used": week_used, "week_remaining": CHAT_WEEKLY_LIMIT - week_used,
    }

def use_chat_token(user_id):
    ym = date.today().strftime("%Y-%m")
    info = get_chat_token_info(user_id)
    supabase.table("chat_tokens").update({
        "used_count": info["used_count"] + 1,
        "updated_at": datetime.now().isoformat()
    }).eq("user_id", user_id).eq("year_month", ym).execute()

def add_chat_extra_tokens(user_id, amount):
    ym = date.today().strftime("%Y-%m")
    info = get_chat_token_info(user_id)
    supabase.table("chat_tokens").update({
        "extra_tokens": info.get("extra_tokens", 0) + amount,
        "updated_at": datetime.now().isoformat()
    }).eq("user_id", user_id).eq("year_month", ym).execute()

