def scan_watched_channel(channel_id, channel_name, max_results=5, assigned_to=None):
    """모니터링 채널의 최신 영상을 자동 스캔"""
    try:
        sr = youtube.search().list(
            part="snippet", channelId=channel_id, type="video",
            maxResults=max_results, order="date", safeSearch="none"
        ).execute()
        results = []
        for item in sr.get("items", []):
            vid = item["id"]["videoId"]
            url = f"https://www.youtube.com/watch?v={vid}"
            title = item["snippet"]["title"]
            desc = item["snippet"].get("description","")[:300]
            published = item["snippet"].get("publishedAt","")[:10]
            comments = get_video_comments(vid, max_comments=20)
            comment_text = "\n".join([f"- {c}" for c in comments[:10]]) if comments else "없음"
            msg = client.messages.create(
                model="claude-sonnet-4-6", max_tokens=300,
                messages=[{"role":"user","content":f"""아동 안전 전문 분석가로서 위험 채널의 최신 영상을 분석하세요.

채널: {channel_name}
제목: {title}
설명: {desc}
댓글: {comment_text}

반드시 아래 형식으로만:
심각도: (1~5)
분류: (안전/부적절/그루밍/섹스토션/도박/폭력유도)
위험신호: (구체적 패턴)
이유: (한 줄)"""}]
            )
            rt = msg.content[0].text
            sev = extract_severity(rt)
            cat = extract_category(rt)
            mark_url_analyzed(url, title, "channel_monitor", assigned_to)
            results.append({
                "id": vid, "title": title, "channel": channel_name,
                "url": url, "analysis": rt, "severity": sev,
                "category": cat, "search_type": "channel_monitor",
                "published": published
            })
        return results
    except Exception as e:
        return []

def get_token_info(user_id):
    ym = date.today().strftime("%Y-%m")
    res = supabase.table("dragon_tokens").select("*").eq("user_id", user_id).eq("year_month", ym).execute()
    if res.data:
        return res.data[0]
    supabase.table("dragon_tokens").insert({
        "user_id": user_id,
        "year_month": ym,
        "used_count": 0,
        "extra_tokens": 0
    }).execute()
    return {"used_count": 0, "extra_tokens": 0}

def get_today_dragon_count(user_id):
    today = date.today().isoformat()
    res = supabase.table("analyzed_urls").select("id").eq("assigned_to", user_id).gte("analyzed_at", today).in_("search_type", ["dragon_general","dragon_roblox","dragon_minecraft"]).execute()
    return len(res.data)

# ════════ 모니터링 자동화 설정 ════════
MONITORING_BACKLOG_LIMIT = 100   # 미처리(미작성)가 이 수 이상이면 추천 생성/주간 배정 자동 중단
WEEKLY_ASSIGN_COUNT = 50         # 매주 월요일 새벽 3시 자동 배정 건수
MONTHLY_MONITOR_LIMIT = 200      # 1인 월 모니터링 상한 (주 50건 × 4주)

def get_user_pending_count(user_id):
    """사용자의 미처리(미작성) 배정 모니터링 건수 — 백로그 자동중단 판정용."""
    try:
        r = supabase.table("analyzed_urls").select("id", count="exact") \
            .eq("assigned_to", user_id).eq("reported", False).execute()
        c = getattr(r, "count", None)
        return c if c is not None else len(r.data or [])
    except Exception:
        return 0

def get_user_month_assigned_count(user_id):
    """이번 달 배정된 모니터링 건수 — 월 200건 상한 판정용."""
    try:
        _m0 = date.today().strftime("%Y-%m-01")
        r = supabase.table("analyzed_urls").select("id", count="exact") \
            .eq("assigned_to", user_id).gte("assigned_at", _m0).execute()
        c = getattr(r, "count", None)
        return c if c is not None else len(r.data or [])
    except Exception:
        return 0

def run_weekly_assignment_all_users(limit_users=None):
    """📅 매주 월요일 자동 배정 배치 — 모니터링 사용자별 WEEKLY_ASSIGN_COUNT(50)건 배정.
    백로그≥100 또는 월배정≥200인 사용자는 건너뜀. (외부 cron 또는 관리자 수동 실행)
    반환: 실행 요약 dict."""
    summary = {"assigned_users": 0, "skipped_backlog": 0, "skipped_monthly": 0,
               "total_videos": 0, "errors": 0, "candidates": 0}
    try:
        uq = supabase.table("users").select("id,name,email,role,is_campaign_only,status").execute()
        users = [u for u in (uq.data or [])
                 if (u.get("status") or "active") == "active" and not u.get("is_campaign_only")]
        if limit_users:
            users = users[:limit_users]
        summary["candidates"] = len(users)
        for u in users:
            uid = u["id"]
            try:
                if get_user_pending_count(uid) >= MONITORING_BACKLOG_LIMIT:
                    summary["skipped_backlog"] += 1
                    continue
                if get_user_month_assigned_count(uid) >= MONTHLY_MONITOR_LIMIT:
                    summary["skipped_monthly"] += 1
                    continue
                assigned_urls = get_analyzed_urls()
                new_cnt = 0
                for plat in ["general", "roblox", "minecraft", "gambling"]:
                    if new_cnt >= WEEKLY_ASSIGN_COUNT:
                        break
                    for kw in generate_recommend_keywords(plat):
                        if new_cnt >= WEEKLY_ASSIGN_COUNT:
                            break
                        try:
                            res = search_and_analyze(
                                kw, max_results=3, analyzed_urls=assigned_urls,
                                search_type=f"dragon_{plat}", assigned_to=uid)
                            for rr in res:
                                assigned_urls.add(rr["url"])
                            new_cnt += len(res)
                        except Exception:
                            summary["errors"] += 1
                if new_cnt > 0:
                    summary["assigned_users"] += 1
                    summary["total_videos"] += new_cnt
            except Exception:
                summary["errors"] += 1
    except Exception:
        pass
    return summary

def use_dragon_token(user_id):
    ym = date.today().strftime("%Y-%m")
    info = get_token_info(user_id)
    supabase.table("dragon_tokens").update({
        "used_count": info["used_count"] + 1,
        "updated_at": datetime.now().isoformat()
    }).eq("user_id", user_id).eq("year_month", ym).execute()

def add_extra_tokens(user_id, amount):
    ym = date.today().strftime("%Y-%m")
    info = get_token_info(user_id)
    supabase.table("dragon_tokens").update({
        "extra_tokens": info.get("extra_tokens", 0) + amount,
        "updated_at": datetime.now().isoformat()
    }).eq("user_id", user_id).eq("year_month", ym).execute()

def can_use_dragon(user_id):
    info = get_token_info(user_id)
    used = info["used_count"]
    extra = info.get("extra_tokens", 0)
    monthly_limit = MONTHLY_DRAGON_LIMIT + extra
    today_used = get_today_dragon_count(user_id)
    return {
        "ok": used < monthly_limit and today_used < DAILY_DRAGON_LIMIT,
        "used": used,
        "monthly_limit": monthly_limit,
        "today_used": today_used,
        "daily_limit": DAILY_DRAGON_LIMIT,
        "monthly_remaining": monthly_limit - used,
        "daily_remaining": DAILY_DRAGON_LIMIT - today_used,
    }

def extract_severity(text):
    for i in range(5, 0, -1):
        if f"심각도: {i}" in text or f"심각도:{i}" in text:
            return i
    return 1

def extract_category(text):
    for cat in ["섹스토션", "폭력유도", "그루밍", "성인", "부적절", "스팸", "안전"]:
        if cat in text:
            return cat
    return "미분류"

def sev_icon(s):
    return {1:"✅", 2:"🟡", 3:"🟠", 4:"🔴", 5:"🚨"}.get(s, "❓")

