def parse_keywords(text):
    keywords = []
    for line in text.strip().split("\n"):
        line = line.strip()
        if line and line[0].isdigit():
            line = line.lstrip("0123456789.-) ").strip()
        if line and len(line) > 1:
            keywords.append(line)
    return keywords[:10]

