def get_video_comments(video_id, max_comments=30):
    """유튜브 영상 댓글 수집 — 위험 패턴 탐지용"""
    try:
        res = youtube.commentThreads().list(
            part="snippet",
            videoId=video_id,
            maxResults=max_comments,
            order="relevance",
            textFormat="plainText"
        ).execute()
        comments = []
        for item in res.get("items", []):
            text = item["snippet"]["topLevelComment"]["snippet"]["textDisplay"]
            if len(text.strip()) > 2:
                comments.append(text.strip()[:200])
        return comments
    except:
        return []  # 댓글 비활성화 or API 오류시 빈 리스트

def search_and_analyze(keyword, max_results=5, analyzed_urls=None, search_type="keyword", assigned_to=None):
    if analyzed_urls is None:
        analyzed_urls = set()

    sr = youtube.search().list(
        part="snippet", q=keyword, type="video",
        maxResults=max_results + 10,
        relevanceLanguage="ko",
        order="date",
        regionCode="KR",
        safeSearch="none"
    ).execute()

    results = []
    for item in sr.get("items", []):
        if len(results) >= max_results:
            break
        vid = item["id"]["videoId"]
        url = f"https://www.youtube.com/watch?v={vid}"
        if url in analyzed_urls:
            continue
        title = item["snippet"]["title"]
        desc = item["snippet"].get("description", "")[:300]
        channel = item["snippet"]["channelTitle"]
        published = item["snippet"].get("publishedAt", "")[:10]

        # 댓글 수집
        comments = get_video_comments(vid, max_comments=30)
        comment_text = ""
        if comments:
            # 위험 키워드 포함 댓글 우선 필터링
            danger_keywords = ["카카오", "카톡", "디스코드", "인스타", "텔레그램",
                              "나이", "학교", "만나", "사진", "영상", "선물",
                              "친구해", "여친", "남친", "좋아해", "사랑해"]
            flagged = [c for c in comments if any(k in c for k in danger_keywords)]
            normal = [c for c in comments if c not in flagged]
            selected = (flagged + normal)[:15]
            comment_text = "\n".join([f"- {c}" for c in selected])

        msg = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=500,
            messages=[{"role": "user", "content": f"""당신은 아동 온라인 안전 전문 분석가입니다. 아래 유튜브 영상이 아동·청소년에게 위험한지 매우 엄격하게 분석하세요.

제목: {title}
채널: {channel}
업로드일: {published}
설명: {desc}
{"댓글 샘플:" + chr(10) + comment_text if comment_text else "댓글: 없음 또는 비활성화"}

【위험 신호 체크리스트 — 하나라도 해당하면 심각도 3 이상】
① 그루밍: 성인이 어린이/청소년에게 친구/연인 관계 유도, 나이 묻기, 학교 묻기
② 연락처 유도: 카카오톡·디스코드·인스타·텔레그램 등 외부 플랫폼으로 이동 유도
③ 성적 접근: 교복·신체·나이 관련 성적 암시, 야한 스킨/모드/서버
④ 개인정보: 주소·학교·전화번호 요구
⑤ 미끼: 무료 아이템·로벅스·게임 코인으로 미성년자 유인
⑥ 협박/섹스토션: 사진·영상 요구 후 유포 협박
⑦ 도박/사행성: 불법 배팅·토토·카지노 사이트 홍보, 첫충/보너스/무료머니 광고, 대리베팅·총판 모집, 파워볼·코인게임 수익인증, "용돈 버는 법" 위장 도박 유도
⑧ 가출/납치: 가출 조장, 만남 장소 공유
⑨ 자해/폭력: 자해 방법, 폭력 챌린지 유도

【댓글 분석 주의사항】
- 댓글에서 연락처 요청, 만남 유도, 나이/학교 묻기 패턴이 있으면 심각도 +1
- 댓글이 없어도 제목/설명만으로 위험 판단 가능

【중요】
- 제목/설명이 애매하거나 의심스러우면 심각도를 높게 잡으세요
- 안전으로 분류하려면 명백히 교육적이거나 공식 채널이어야 함

반드시 아래 형식으로만 답변하세요:
심각도: (1~5)
분류: (안전/스팸/부적절/성인/그루밍/섹스토션/도박/폭력유도/개인정보침해)
위험신호: (발견된 위험 패턴 구체적으로, 없으면 "없음")
이유: (한 줄 요약)"""}]
        )
        rt = msg.content[0].text
        sev = extract_severity(rt)
        cat = extract_category(rt)

        # 드래곤아이즈 추천: AI 판정과 무관하게 모든 결과 노출
        # 사유: YouTube 안전 필터는 신고된 후만 작동. 사전 모니터링은 인간 검토 필수.
        # AI 심각도 점수는 참고용으로만 표시. 최종 판단은 전문 모니터가 수행.
        # 도박만 예외: 공식 채널 등 명백한 안전 콘텐츠는 자동 제외
        if search_type == "dragon_gambling" and sev <= 1 and cat == "안전":
            analyzed_urls.add(url)
            mark_url_analyzed(url, title, search_type, assigned_to)
            continue

        mark_url_analyzed(url, title, search_type, assigned_to)
        # 심각도 3 이상이면 채널 자동 모니터링 등록
        if sev >= 3:
            register_watched_channel(
                channel_id=item["snippet"]["channelId"],
                channel_name=channel,
                severity=sev,
                added_by=assigned_to
            )
        results.append({
            "id": vid, "title": title, "channel": channel,
            "url": url, "keyword": keyword, "analysis": rt,
            "severity": sev, "category": cat, "search_type": search_type,
            "published": published
        })
        analyzed_urls.add(url)
    return results

def render_custom_pwreset_page():
    """🔑 커스텀 비밀번호 재설정 페이지 (Resend 토큰 링크). 로그인 불필요.
    우리가 직접 발급한 토큰을 검증 → 본인 확인 → 새 비밀번호 설정(admin API).
    Supabase Site URL/Redirect 설정과 무관하게 동작."""
    import datetime as _dtt
    _token = st.session_state.get("_pwreset_token") or st.query_params.get("pwreset_token")
    st.markdown("## 🔑 비밀번호 재설정")
    if not _token:
        st.error("유효하지 않은 접근입니다.")
        return
    # 토큰으로 사용자 조회 (사용자 수가 적어 전체 조회 후 매칭 — JSON 필터 의존 제거)
    _u = None
    try:
        _all = supabase.table("users").select("id,name,email,preferences").execute().data or []
        _u = next((x for x in _all
                   if (x.get("preferences") or {}).get("pwreset_token") == _token), None)
    except Exception as _e:
        st.error(f"조회 실패: {str(_e)[:200]}")
        return
    _valid = False
    if _u:
        _exp = (_u.get("preferences") or {}).get("pwreset_expires")
        try:
            if _exp and _dtt.datetime.fromisoformat(_exp) > _dtt.datetime.now():
                _valid = True
        except Exception:
            _valid = False
    if not _valid:
        st.error("⛔ 재설정 링크가 만료되었거나 유효하지 않습니다. (유효시간 30분)")
        st.caption("로그인 화면에서 '비밀번호를 잊으셨나요?'로 다시 요청해주세요.")
        if st.button("← 로그인 화면으로", key="cpr_back"):
            st.session_state["current_page"] = None
            st.session_state.pop("_pwreset_token", None)
            try:
                if "pwreset_token" in st.query_params:
                    del st.query_params["pwreset_token"]
            except Exception:
                pass
            st.rerun()
        return
    st.success(f"✅ 본인 확인 완료 — {_u.get('email','')}")
    st.caption("새 비밀번호를 설정해주세요.")
    _p1 = st.text_input("새 비밀번호 (6자 이상)", type="password", key="cpr_pw1")
    _p2 = st.text_input("새 비밀번호 확인", type="password", key="cpr_pw2")
    if st.button("✅ 비밀번호 변경", type="primary", use_container_width=True, key="cpr_do"):
        if not _p1 or len(_p1) < 6:
            st.error("비밀번호는 6자 이상이어야 합니다.")
        elif _p1 != _p2:
            st.error("비밀번호가 일치하지 않습니다.")
        else:
            try:
                sb_admin().auth.admin.update_user_by_id(_u["id"], {"password": _p1})
                # 토큰 폐기
                _prefs = _u.get("preferences") or {}
                _prefs.pop("pwreset_token", None)
                _prefs.pop("pwreset_expires", None)
                supabase.table("users").update({"preferences": _prefs}).eq("id", _u["id"]).execute()
                st.session_state.pop("_pwreset_token", None)
                try:
                    if "pwreset_token" in st.query_params:
                        del st.query_params["pwreset_token"]
                except Exception:
                    pass
                st.session_state["current_page"] = None
                st.success("🎉 비밀번호가 변경되었습니다! 로그인 화면에서 새 비밀번호로 로그인하세요.")
                st.balloons()
            except Exception as _e2:
                st.error(f"❌ 변경 실패: {str(_e2)[:300]}")
                st.caption("‘User not allowed’ 류면 서버에 SUPABASE_SERVICE_ROLE_KEY 설정이 필요합니다.")


def render_password_reset_recovery_page(user):
    """🔐 비밀번호 재설정 복구 모드 — 이메일 복구 링크로 본인확인된 사용자가
    새 비밀번호를 직접 설정. 설정 전까지 다른 화면 접근 차단."""
    _lang = st.session_state.get("lang", "ko")
    _TXT = {
        "ko": {"title":"🔑 새 비밀번호 설정",
               "info":"본인 확인이 완료되었습니다. 새 비밀번호를 설정해주세요.",
               "pw1":"새 비밀번호","pw2":"새 비밀번호 확인",
               "submit":"✅ 비밀번호 변경","cancel":"취소(로그아웃)",
               "short":"비밀번호는 6자 이상이어야 합니다.","mismatch":"비밀번호가 일치하지 않습니다.",
               "ok":"✅ 비밀번호가 변경되었습니다. 잠시 후 메인으로 이동합니다.","fail":"변경 실패"},
        "en": {"title":"🔑 Set a new password",
               "info":"Your identity is verified. Please set a new password.",
               "pw1":"New password","pw2":"Confirm new password",
               "submit":"✅ Change password","cancel":"Cancel (log out)",
               "short":"Password must be at least 6 characters.","mismatch":"Passwords do not match.",
               "ok":"✅ Password changed. Redirecting shortly.","fail":"Failed"},
        "ja": {"title":"🔑 新しいパスワードの設定",
               "info":"本人確認が完了しました。新しいパスワードを設定してください。",
               "pw1":"新しいパスワード","pw2":"新しいパスワード（確認）",
               "submit":"✅ パスワード変更","cancel":"キャンセル（ログアウト）",
               "short":"パスワードは6文字以上にしてください。","mismatch":"パスワードが一致しません。",
               "ok":"✅ パスワードを変更しました。まもなくメインへ移動します。","fail":"失敗"},
    }
    _x = _TXT.get(_lang, _TXT["ko"])
    st.markdown(f"## {_x['title']}")
    st.info(f"{_x['info']}  ({user.get('email','')})")
    pw1 = st.text_input(_x["pw1"], type="password", key="pwrec_pw1")
    pw2 = st.text_input(_x["pw2"], type="password", key="pwrec_pw2")
    c1, c2 = st.columns(2)
    with c1:
        if st.button(_x["submit"], type="primary", use_container_width=True, key="pwrec_submit"):
            if not pw1 or len(pw1) < 6:
                st.error(_x["short"])
            elif pw1 != pw2:
                st.error(_x["mismatch"])
            else:
                try:
                    supabase.auth.update_user({"password": pw1})
                    st.session_state.pop("_pw_recovery_mode", None)
                    try:
                        if "pwreset" in st.query_params:
                            del st.query_params["pwreset"]
                    except Exception:
                        pass
                    st.success(_x["ok"])
                    st.balloons()
                    import time as _t; _t.sleep(1.5)
                    st.rerun()
                except Exception as e:
                    st.error(f"{_x['fail']}: {e}")
    with c2:
        if st.button(_x["cancel"], use_container_width=True, key="pwrec_cancel"):
            st.session_state.pop("_pw_recovery_mode", None)
            try: supabase.auth.sign_out()
            except Exception: pass
            for _k in list(st.session_state.keys()):
                try: del st.session_state[_k]
                except Exception: pass
            try: st.query_params.clear()
            except Exception: pass
            st.rerun()

# 🔑 커스텀 비밀번호 재설정 (토큰 링크) — 로그인 여부와 무관하게 최우선 처리
