    # ── 카테고리 그래프 데이터 (직전 달 기준, 매월 자동 갱신 시도) ──
    @st.cache_data(ttl=86400)  # 24시간 캐싱
    def _get_login_category_stats():
        """직전 달 카테고리 분포 (% 비율). 데이터 부족 시 fallback 고정값."""
        try:
            from datetime import datetime, timedelta
            today = datetime.now()
            first_this_month = today.replace(day=1)
            last_month_end = first_this_month - timedelta(days=1)
            last_month_start = last_month_end.replace(day=1)
            start_iso = last_month_start.strftime("%Y-%m-%d")
            end_iso = (first_this_month).strftime("%Y-%m-%d")
            res = supabase.table("reports").select("risk_category").gte("created_at", start_iso).lt("created_at", end_iso).execute()
            rows = res.data or []
            if len(rows) < 30:
                return None
            from collections import Counter
            cnt = Counter()
            for r in rows:
                cat = (r.get("risk_category") or "").strip()
                if "그루밍" in cat: cnt["grooming"] += 1
                elif "도박" in cat: cnt["gambling"] += 1
                elif "섹스토션" in cat or "성착취" in cat: cnt["sextortion"] += 1
                elif "부적절" in cat or "음란" in cat: cnt["inappropriate"] += 1
                else: cnt["other"] += 1
            total = sum(cnt.values()) or 1
            return {k: round(v * 100 / total) for k, v in cnt.items()}
        except Exception:
            return None

    _stats = _get_login_category_stats() or {
        "grooming": 38, "gambling": 24, "sextortion": 16, "inappropriate": 12, "other": 10
    }

