            st.caption(f"{t('written_at')}: {str(r.get('created_at',''))[:16]}" +
                      (f"  |  {t('updated_at')}: {str(r.get('updated_at',''))[:16]}" if r.get('updated_at') else ""))

            # 보고서 고유번호 + 탐색 URL 연결 표시
