        # ── 오른쪽: 통계 (상단) + 모니터링 버튼 (하단) ──
        with right_col:

            st.markdown(f'<div style="font-size:0.82rem; font-weight:600; color:#94a3b8; margin:0 0 4px 0;">📊 {t("admin_team")[:5]}</div>', unsafe_allow_html=True)

